/**
 * Captura assinaturas das stores utilizadas
 * pela reidratação visual.
 */
async function capturarEstadoStoresReidratacaoUX1987_() {
  const configuracoes = [
    {
      store: "TB_DIARIOS",
      chave: "idDiario"
    },
    {
      store: "TB_DIARIO_ITENS",
      chave: "idItemDiario"
    },
    {
      store: "TB_OCORRENCIAS",
      chave: "idOcorrencia"
    },
    {
      store: "TB_CLIMA",
      chave: "idClima"
    },
    {
      store: "TB_EVIDENCIAS",
      chave: "idEvidencia"
    },
    {
      store: "TB_SYNC_QUEUE",
      chave: "idSyncLocal"
    }
  ];

  const estado = {};

  for (const configuracao of configuracoes) {
    const registros =
      await listarRegistrosSIGO(
        configuracao.store
      );

    estado[configuracao.store] = {
      quantidade:
        registros.length,

      assinatura:
        criarAssinaturaColecaoEvidenciasUX1985_(
          registros,
          configuracao.chave
        )
    };
  }

  return estado;
}


/**
 * Compara o estado das stores antes e depois
 * da pré-visualização.
 */
function compararEstadoStoresReidratacaoUX1987_(
  antes,
  depois
) {
  const stores =
    Object.keys(antes || {});

  const divergencias = [];

  stores.forEach(function (store) {
    const estadoAntes =
      antes?.[store];

    const estadoDepois =
      depois?.[store];

    if (
      !estadoDepois ||
      estadoAntes.quantidade !==
        estadoDepois.quantidade ||
      estadoAntes.assinatura !==
        estadoDepois.assinatura
    ) {
      divergencias.push({
        store:
          store,

        quantidadeAntes:
          estadoAntes?.quantidade,

        quantidadeDepois:
          estadoDepois?.quantidade
      });
    }
  });

  return {
    preservadas:
      divergencias.length === 0,

    divergencias:
      divergencias
  };
}


