/**
 * ============================================================
 * UX.20.1 — CONFIGURAÇÃO PERSISTENTE DO HISTÓRICO OFFLINE
 * ============================================================
 *
 * Períodos permitidos:
 *
 * - 15 dias
 * - 30 dias
 * - 60 dias
 * - 90 dias
 *
 * A configuração:
 *
 * - pertence ao dispositivo/navegador;
 * - não entra na fila de sincronização;
 * - não altera nenhuma store do IndexedDB;
 * - não remove registros antigos;
 * - é utilizada pelas APIs de reidratação.
 */

const PERIODOS_HISTORICO_OFFLINE_UX201 =
  Object.freeze([
    15,
    30,
    60,
    90
  ]);

const PERIODO_PADRAO_HISTORICO_UX201 =
  30;

const CHAVE_HISTORICO_OFFLINE_UX201 =
  "SIGO_CONFIG_HISTORICO_OFFLINE_DIAS_V1";

const CHAVE_META_HISTORICO_UX201 =
  "SIGO_CONFIG_HISTORICO_OFFLINE_META_V1";


/**
 * Normaliza um valor apenas quando ele pertence
 * ao conjunto permitido.
 */
function normalizarPeriodoHistoricoUX201_(
  valor,
  fallback = null
) {
  const numero =
    Number.parseInt(
      String(
        valor === undefined ||
        valor === null
          ? ""
          : valor
      ).trim(),
      10
    );

  if (
    PERIODOS_HISTORICO_OFFLINE_UX201
      .includes(numero)
  ) {
    return numero;
  }

  return fallback;
}


/**
 * Retorna a preferência persistida.
 *
 * Caso ainda não exista ou esteja inválida,
 * registra automaticamente o padrão de 30 dias.
 */
function obterPeriodoHistoricoOfflineUX201_() {
  let valorPersistido = null;

  try {
    valorPersistido =
      localStorage.getItem(
        CHAVE_HISTORICO_OFFLINE_UX201
      );

  } catch (erro) {
    console.warn(
      "[UX.20.1] Não foi possível ler o localStorage:",
      erro
    );
  }

  const periodoValido =
    normalizarPeriodoHistoricoUX201_(
      valorPersistido,
      null
    );

  if (periodoValido !== null) {
    return periodoValido;
  }

  try {
    localStorage.setItem(
      CHAVE_HISTORICO_OFFLINE_UX201,
      String(
        PERIODO_PADRAO_HISTORICO_UX201
      )
    );

    localStorage.setItem(
      CHAVE_META_HISTORICO_UX201,
      JSON.stringify({
        periodoDias:
          PERIODO_PADRAO_HISTORICO_UX201,

        origem:
          "PADRAO_DO_SISTEMA",

        atualizadoEm:
          new Date().toISOString()
      })
    );

  } catch (erro) {
    console.warn(
      "[UX.20.1] Não foi possível persistir o período padrão:",
      erro
    );
  }

  return PERIODO_PADRAO_HISTORICO_UX201;
}


/**
 * Salva uma preferência válida.
 *
 * Valores diferentes de 15, 30, 60 ou 90
 * são rejeitados.
 */
function salvarPeriodoHistoricoOfflineUX201_(
  valor,
  origem = "INTERFACE"
) {
  const periodo =
    normalizarPeriodoHistoricoUX201_(
      valor,
      null
    );

  if (periodo === null) {
    throw new RangeError(
      "Período inválido. Utilize somente 15, 30, 60 ou 90 dias."
    );
  }

  localStorage.setItem(
    CHAVE_HISTORICO_OFFLINE_UX201,
    String(periodo)
  );

  localStorage.setItem(
    CHAVE_META_HISTORICO_UX201,
    JSON.stringify({
      periodoDias:
        periodo,

      origem:
        String(origem || "INTERFACE"),

      atualizadoEm:
        new Date().toISOString()
    })
  );

  aplicarPeriodoHistoricoNaInterfaceUX201_(
    periodo,
    false
  );

  console.log(
    "[UX.20.1] Histórico offline configurado:",
    periodo,
    "dias."
  );

  return periodo;
}


/**
 * Resolve o período que será utilizado por uma API.
 *
 * Um valor explícito válido tem prioridade.
 * Caso contrário, usa a preferência do dispositivo.
 */
function resolverPeriodoHistoricoOfflineUX201_(
  valor
) {
  const periodoExplicito =
    normalizarPeriodoHistoricoUX201_(
      valor,
      null
    );

  if (periodoExplicito !== null) {
    return periodoExplicito;
  }

  return obterPeriodoHistoricoOfflineUX201_();
}


/**
 * Localiza o select do período de reidratação.
 *
 * Primeiro procura IDs conhecidos.
 * Depois procura semanticamente dentro da interface.
 */
function obterSelectPeriodoHistoricoUX201_() {
  const idsConhecidos = [
    "periodoReidratacaoUX1958",
    "diasHistoricoUX1958",
    "historicoReidratacaoUX1958",
    "periodoHistoricoUX1958",
    "selectPeriodoReidratacaoUX1958",
    "diasReidratacaoUX1958"
  ];

  for (const id of idsConhecidos) {
    const elemento =
      document.getElementById(id);

    if (
      elemento &&
      elemento.tagName === "SELECT"
    ) {
      return elemento;
    }
  }

  const seletoresSemanticos = [
    'select[data-periodo-reidratacao]',
    'select[data-historico-offline]',
    'select[name*="historico" i]',
    'select[name*="periodo" i]',
    'select[id*="historico" i]',
    'select[id*="periodo" i][id*="reidrat" i]'
  ];

  for (
    const seletor of seletoresSemanticos
  ) {
    const elemento =
      document.querySelector(seletor);

    if (elemento) {
      return elemento;
    }
  }

  /*
   * Último recurso:
   * procura um select que já contenha as quatro opções.
   */
  const selects =
    Array.from(
      document.querySelectorAll("select")
    );

  return (
    selects.find(
      function (select) {
        const valores =
          Array.from(select.options)
            .map(
              function (option) {
                return Number(
                  option.value
                );
              }
            );

        return PERIODOS_HISTORICO_OFFLINE_UX201
          .every(
            function (periodo) {
              return valores.includes(
                periodo
              );
            }
          );
      }
    ) || null
  );
}


/**
 * Garante que o select possua exclusivamente
 * as opções oficiais.
 */
function garantirOpcoesPeriodoHistoricoUX201_(
  select
) {
  if (!select) {
    return false;
  }

  const valoresAtuais =
    Array.from(select.options)
      .map(
        function (option) {
          return Number(
            option.value
          );
        }
      )
      .filter(
        function (valor) {
          return Number.isFinite(valor);
        }
      );

  const possuiOpcoesCorretas =
    valoresAtuais.length ===
      PERIODOS_HISTORICO_OFFLINE_UX201.length &&

    PERIODOS_HISTORICO_OFFLINE_UX201
      .every(
        function (periodo) {
          return valoresAtuais.includes(
            periodo
          );
        }
      );

  if (!possuiOpcoesCorretas) {
    select.innerHTML =
      PERIODOS_HISTORICO_OFFLINE_UX201
        .map(
          function (periodo) {
            return (
              '<option value="' +
              periodo +
              '">' +
              periodo +
              " dias</option>"
            );
          }
        )
        .join("");
  }

  select.dataset.historicoOffline =
    "true";

  select.dataset.ux201Instalado =
    "true";

  return true;
}


/**
 * Localiza a área visual de “Última atualização”.
 */
function obterAreaUltimaAtualizacaoUX201_() {
  const idsConhecidos = [
    "ultimaAtualizacaoObraUX1958",
    "ultimaAtualizacaoReidratacaoUX1958",
    "textoUltimaAtualizacaoUX1958",
    "cardUltimaAtualizacaoUX1958",
    "ultimaAtualizacaoObraMobile"
  ];

  for (const id of idsConhecidos) {
    const elemento =
      document.getElementById(id);

    if (elemento) {
      return elemento;
    }
  }

  const candidatos =
    Array.from(
      document.querySelectorAll(
        '[id*="ultima" i][id*="atual" i], ' +
        '[class*="ultima" i][class*="atual" i]'
      )
    );

  const candidatoPorTexto =
    candidatos.find(
      function (elemento) {
        return /última atualização|ultima atualizacao/i
          .test(
            String(
              elemento.textContent || ""
            )
          );
      }
    );

  return candidatoPorTexto || null;
}


/**
 * ============================================================
 * UX.20.1A — INDICADOR VISUAL ROBUSTO
 * ============================================================
 *
 * Prioridades de ancoragem:
 *
 * 1. área de Última atualização;
 * 2. container do select de período;
 * 3. modal de reidratação.
 */
function atualizarIndicadorHistoricoUX201_(
  periodo
) {
  const periodoResolvido =
    resolverPeriodoHistoricoOfflineUX201_(
      periodo
    );

  const select =
    obterSelectPeriodoHistoricoUX201_();

  const areaUltimaAtualizacao =
    obterAreaUltimaAtualizacaoUX201_();

  const modalReidratacao =
    document.getElementById(
      "modalReidratacaoUX1958"
    ) ||
    document.querySelector(
      '[id*="reidratacao" i], ' +
      '[id*="reidrat" i][role="dialog"]'
    );

  let indicador =
    document.getElementById(
      "indicadorHistoricoOfflineUX201"
    );

  if (!indicador) {
    indicador =
      document.createElement("div");

    indicador.id =
      "indicadorHistoricoOfflineUX201";

    indicador.className =
      "sigo-indicador-historico-offline";

    indicador.setAttribute(
      "aria-live",
      "polite"
    );

    indicador.style.marginTop =
      "7px";

    indicador.style.fontSize =
      "12px";

    indicador.style.lineHeight =
      "1.4";

    indicador.style.fontWeight =
      "600";

    indicador.style.opacity =
      "0.78";

    indicador.style.display =
      "flex";

    indicador.style.alignItems =
      "center";

    indicador.style.gap =
      "5px";
  }

  const textoEsperado =
    "Histórico offline: " +
    periodoResolvido +
    " dias";

  /*
   * Evita disparar o MutationObserver repetidamente
   * quando o texto já estiver correto.
   */
  if (
    indicador.textContent !==
    textoEsperado
  ) {
    indicador.textContent =
      textoEsperado;
  }

  indicador.dataset.periodoDias =
    String(periodoResolvido);

  indicador.dataset.ux201a =
    "true";


  /*
   * 1. Preferência: área de Última atualização.
   */
  if (areaUltimaAtualizacao) {
    const container =
      areaUltimaAtualizacao.matches(
        "input, select, textarea"
      )
        ? areaUltimaAtualizacao.parentElement
        : areaUltimaAtualizacao;

    if (
      container &&
      indicador.parentElement !==
        container
    ) {
      container.appendChild(
        indicador
      );
    }

    return true;
  }


  /*
   * 2. Fallback principal:
   * posiciona imediatamente após o select.
   */
  if (select) {
    if (
      indicador.previousElementSibling !==
        select ||
      indicador.parentElement !==
        select.parentElement
    ) {
      select.insertAdjacentElement(
        "afterend",
        indicador
      );
    }

    return true;
  }


  /*
   * 3. Último fallback:
   * adiciona dentro do modal de reidratação.
   */
  if (modalReidratacao) {
    if (
      indicador.parentElement !==
      modalReidratacao
    ) {
      modalReidratacao.appendChild(
        indicador
      );
    }

    return true;
  }

  console.warn(
    "[UX.20.1A] Não foi encontrado um container para o indicador visual."
  );

  return false;
}


/**
 * Aplica a preferência ao select e ao card.
 */
function aplicarPeriodoHistoricoNaInterfaceUX201_(
  periodo = null,
  forcarSelect = true
) {
  const periodoResolvido =
    resolverPeriodoHistoricoOfflineUX201_(
      periodo
    );

  const select =
    obterSelectPeriodoHistoricoUX201_();

  if (select) {
    garantirOpcoesPeriodoHistoricoUX201_(
      select
    );

    const valorAtual =
      normalizarPeriodoHistoricoUX201_(
        select.value,
        null
      );

    if (
      forcarSelect ||
      valorAtual === null
    ) {
      select.value =
        String(periodoResolvido);
    }
  }

  atualizarIndicadorHistoricoUX201_(
    periodoResolvido
  );

  return {
    periodoDias:
      periodoResolvido,

    selectEncontrado:
      Boolean(select),

    valorSelect:
      select?.value || "",

    indicadorAtualizado:
      Boolean(
        document.getElementById(
          "indicadorHistoricoOfflineUX201"
        )
      )
  };
}


/**
 * Adapta argumentos de clientes Mobile.
 */
function adaptarArgumentosClienteHistoricoUX201_(
  argumentos
) {
  const args =
    Array.from(argumentos);

  /*
   * Contrato por payload:
   *
   * cliente({
   *   idObra,
   *   diasHistorico
   * })
   */
  if (
    args[0] &&
    typeof args[0] === "object" &&
    !Array.isArray(args[0])
  ) {
    const payload = {
      ...args[0]
    };

    payload.diasHistorico =
      resolverPeriodoHistoricoOfflineUX201_(
        payload.diasHistorico ??
        payload.periodoDias
      );

    payload.periodoDias =
      payload.diasHistorico;

    args[0] =
      payload;

    return args;
  }

  /*
   * Contrato tradicional:
   *
   * cliente(idObra, periodoDias)
   */
  args[1] =
    resolverPeriodoHistoricoOfflineUX201_(
      args[1]
    );

  return args;
}


/**
 * Protege um cliente Mobile individual.
 */
function envolverClienteHistoricoUX201_(
  nomeFuncao
) {
  const funcaoAtual =
    window[nomeFuncao];

  if (
    typeof funcaoAtual !== "function"
  ) {
    return false;
  }

  if (
    funcaoAtual.__ux201Protegida === true
  ) {
    return true;
  }

  async function clienteComHistoricoUX201_(
    ...argumentos
  ) {
    const argumentosResolvidos =
      adaptarArgumentosClienteHistoricoUX201_(
        argumentos
      );

    return funcaoAtual.apply(
      this,
      argumentosResolvidos
    );
  }

  clienteComHistoricoUX201_
    .__ux201Protegida = true;

  clienteComHistoricoUX201_
    .__ux201Original = funcaoAtual;

  window[nomeFuncao] =
    clienteComHistoricoUX201_;

  return true;
}


/**
 * Instala a preferência nos clientes de todas
 * as entidades reidratadas.
 */
function instalarClientesHistoricoUX201_() {
  const clientes = [
    "obterDadosOperacionaisObraMobile_",
    "obterOcorrenciasOperacionaisObraMobile_",
    "obterClimasOperacionaisObraMobile_",
    "obterEvidenciasOperacionaisObraMobile_",
    "obterMedicoesOficiaisObraMobile_"
  ];

  const resultado = {};

  clientes.forEach(
    function (nomeFuncao) {
      resultado[nomeFuncao] =
        envolverClienteHistoricoUX201_(
          nomeFuncao
        );
    }
  );

  return resultado;
}


/**
 * Salva a opção selecionada antes de visualizar
 * ou confirmar uma reidratação.
 */
function salvarSelecaoAtualHistoricoUX201_(
  origem
) {
  const select =
    obterSelectPeriodoHistoricoUX201_();

  if (!select) {
    return obterPeriodoHistoricoOfflineUX201_();
  }

  try {
    return salvarPeriodoHistoricoOfflineUX201_(
      select.value,
      origem
    );

  } catch (erro) {
    console.error(
      "[UX.20.1] Seleção rejeitada:",
      erro
    );

    const periodoAtual =
      obterPeriodoHistoricoOfflineUX201_();

    select.value =
      String(periodoAtual);

    throw erro;
  }
}


/**
 * Instala listeners e observação da interface.
 */
function instalarConfiguracaoHistoricoOfflineUX201_() {
  window.SIGO_UX201 =
    window.SIGO_UX201 || {};

  if (
    window.SIGO_UX201.instalado === true
  ) {
    aplicarPeriodoHistoricoNaInterfaceUX201_();

    return {
      instalado:
        true,

      repetido:
        true,

      periodoDias:
        obterPeriodoHistoricoOfflineUX201_()
    };
  }

  window.SIGO_UX201.instalado =
    true;

  window.SIGO_UX201.clientes =
    instalarClientesHistoricoUX201_();


  /*
   * Alteração manual do select.
   */
  document.addEventListener(
    "change",
    function (evento) {
      const select =
        evento.target;

      if (
        !select ||
        select.tagName !== "SELECT"
      ) {
        return;
      }

      const selectOficial =
        obterSelectPeriodoHistoricoUX201_();

      if (
        select !== selectOficial &&
        select.dataset
          ?.historicoOffline !==
          "true"
      ) {
        return;
      }

      try {
        salvarPeriodoHistoricoOfflineUX201_(
          select.value,
          "ALTERACAO_USUARIO"
        );

      } catch (erro) {
        console.error(
          "[UX.20.1] Período inválido:",
          erro
        );

        select.value =
          String(
            obterPeriodoHistoricoOfflineUX201_()
          );
      }
    },
    true
  );


  /*
   * Captura antes dos handlers anteriores de
   * visualizar e confirmar.
   */
  document.addEventListener(
    "click",
    function (evento) {
      const botao =
        evento.target?.closest?.(
          "#visualizarReidratacaoUX1958, " +
          "#confirmarReidratacaoUX1958"
        );

      if (!botao) {
        return;
      }

      salvarSelecaoAtualHistoricoUX201_(
        botao.id ===
          "confirmarReidratacaoUX1958"
          ? "CONFIRMACAO_REIDRATACAO"
          : "PRE_VISUALIZACAO_REIDRATACAO"
      );
    },
    true
  );


  /*
   * Observa interfaces criadas dinamicamente.
   */
  let agendamento = null;

  const observer =
    new MutationObserver(
      function () {
        clearTimeout(agendamento);

        agendamento =
          setTimeout(
            function () {
              aplicarPeriodoHistoricoNaInterfaceUX201_(
                null,
                false
              );
            },
            50
          );
      }
    );

  observer.observe(
    document.documentElement,
    {
      childList:
        true,

      subtree:
        true
    }
  );

  window.SIGO_UX201.observer =
    observer;

  const interfaceInicial =
    aplicarPeriodoHistoricoNaInterfaceUX201_(
      obterPeriodoHistoricoOfflineUX201_(),
      true
    );

  console.log(
    "UX.20.1 — Configuração persistente do histórico offline instalada.",
    interfaceInicial
  );

  return {
    instalado:
      true,

    repetido:
      false,

    periodoDias:
      obterPeriodoHistoricoOfflineUX201_(),

    clientes:
      window.SIGO_UX201.clientes,

    interface:
      interfaceInicial
  };
}


/**
 * Resumo da configuração atual.
 */
function obterResumoHistoricoOfflineUX201_() {
  let metadados = null;

  try {
    metadados =
      JSON.parse(
        localStorage.getItem(
          CHAVE_META_HISTORICO_UX201
        ) || "null"
      );

  } catch (erro) {
    metadados = null;
  }

  const select =
    obterSelectPeriodoHistoricoUX201_();

  return {
    etapa:
      "UX.20.1",

    periodoDias:
      obterPeriodoHistoricoOfflineUX201_(),

    periodosPermitidos:
      [
        ...PERIODOS_HISTORICO_OFFLINE_UX201
      ],

    persistencia:
      "LOCAL_STORAGE_DISPOSITIVO",

    metadados:
      metadados,

    interface: {
      selectEncontrado:
        Boolean(select),

      valorSelect:
        select?.value || "",

      indicadorEncontrado:
        Boolean(
          document.getElementById(
            "indicadorHistoricoOfflineUX201"
          )
        )
    },

    limpezaAutomatica:
      false
  };
}


/**
 * Instalação automática.
 */
if (
  document.readyState === "loading"
) {
  document.addEventListener(
    "DOMContentLoaded",
    function () {
      instalarConfiguracaoHistoricoOfflineUX201_();
    },
    {
      once:
        true
    }
  );

} else {
  instalarConfiguracaoHistoricoOfflineUX201_();
}

/**
 * ============================================================
 * UX.20.1 — AUDITORIA DA CONFIGURAÇÃO PERSISTENTE
 * ============================================================
 *
 * Não chama APIs.
 * Não executa reidratação.
 * Não altera IndexedDB.
 */
async function auditarConfiguracaoHistoricoOfflineUX201_() {
  console.log(
    "[UX.20.1] Iniciando auditoria da configuração persistente..."
  );

  const storesAuditadas = [
    "TB_DIARIOS",
    "TB_DIARIO_ITENS",
    "TB_OCORRENCIAS",
    "TB_CLIMA",
    "TB_EVIDENCIAS",
    "TB_MEDICOES",
    "TB_LOTES_MEDICAO",
    "TB_SYNC_QUEUE",
    "TB_NOTIFICACOES"
  ];

  async function capturarStores_() {
    const resultado = {};

    for (const nomeStore of storesAuditadas) {
      const registros =
        await lerStoreBrutaUX1997A_(
          nomeStore
        );

      resultado[nomeStore] = {
        quantidade:
          registros.length,

        assinatura:
          criarAssinaturaStoreMedicoesUX1994_(
            registros
          )
      };
    }

    return resultado;
  }


  const storesAntes =
    await capturarStores_();

  const valorOriginal =
    obterPeriodoHistoricoOfflineUX201_();

  const metaOriginal =
    localStorage.getItem(
      CHAVE_META_HISTORICO_UX201
    );

  const resultadosPersistencia = {};

  for (
    const periodo of
    PERIODOS_HISTORICO_OFFLINE_UX201
  ) {
    salvarPeriodoHistoricoOfflineUX201_(
      periodo,
      "AUDITORIA_UX201"
    );

    resultadosPersistencia[periodo] =
      Number(
        localStorage.getItem(
          CHAVE_HISTORICO_OFFLINE_UX201
        )
      ) === periodo &&
      obterPeriodoHistoricoOfflineUX201_() ===
        periodo;
  }


  let valorInvalidoRejeitado =
    false;

  try {
    salvarPeriodoHistoricoOfflineUX201_(
      45,
      "AUDITORIA_VALOR_INVALIDO"
    );

  } catch (erro) {
    valorInvalidoRejeitado =
      erro instanceof RangeError;
  }


  /*
   * Restaura exatamente a preferência anterior.
   */
  localStorage.setItem(
    CHAVE_HISTORICO_OFFLINE_UX201,
    String(valorOriginal)
  );

  if (metaOriginal !== null) {
    localStorage.setItem(
      CHAVE_META_HISTORICO_UX201,
      metaOriginal
    );

  } else {
    localStorage.removeItem(
      CHAVE_META_HISTORICO_UX201
    );
  }

  aplicarPeriodoHistoricoNaInterfaceUX201_(
    valorOriginal,
    true
  );


  const select =
    obterSelectPeriodoHistoricoUX201_();

  const opcoesSelect =
    select
      ? Array.from(select.options)
          .map(
            function (option) {
              return Number(
                option.value
              );
            }
          )
      : [];

  const clientes = [
    "obterDadosOperacionaisObraMobile_",
    "obterOcorrenciasOperacionaisObraMobile_",
    "obterClimasOperacionaisObraMobile_",
    "obterEvidenciasOperacionaisObraMobile_",
    "obterMedicoesOficiaisObraMobile_"
  ];

  const clientesProtegidos = {};

  clientes.forEach(
    function (nomeFuncao) {
      clientesProtegidos[nomeFuncao] =
        typeof window[nomeFuncao] ===
          "function" &&
        window[nomeFuncao]
          .__ux201Protegida ===
          true;
    }
  );


  const storesDepois =
    await capturarStores_();

  const storesPreservadas = {};

  storesAuditadas.forEach(
    function (nomeStore) {
      storesPreservadas[nomeStore] =
        storesAntes[nomeStore]
          .quantidade ===
          storesDepois[nomeStore]
            .quantidade &&

        storesAntes[nomeStore]
          .assinatura ===
          storesDepois[nomeStore]
            .assinatura;
    }
  );


  const validacoes = {
    periodoPadraoConfigurado:
      valorOriginal === 15 ||
      valorOriginal === 30 ||
      valorOriginal === 60 ||
      valorOriginal === 90,

    salvou15:
      resultadosPersistencia[15] ===
      true,

    salvou30:
      resultadosPersistencia[30] ===
      true,

    salvou60:
      resultadosPersistencia[60] ===
      true,

    salvou90:
      resultadosPersistencia[90] ===
      true,

    rejeitou45:
      valorInvalidoRejeitado === true,

    preferenciaOriginalRestaurada:
      obterPeriodoHistoricoOfflineUX201_() ===
      valorOriginal,

    selectEncontrado:
      Boolean(select),

    selectPossuiQuatroOpcoes:
      opcoesSelect.length === 4,

    selectPossui15:
      opcoesSelect.includes(15),

    selectPossui30:
      opcoesSelect.includes(30),

    selectPossui60:
      opcoesSelect.includes(60),

    selectPossui90:
      opcoesSelect.includes(90),

    selectMostraPreferencia:
      Number(select?.value) ===
      valorOriginal,

    indicadorVisualCriado:
      Boolean(
        document.getElementById(
          "indicadorHistoricoOfflineUX201"
        )
      ),

    todosClientesProtegidos:
      Object.values(
        clientesProtegidos
      ).every(
        function (valor) {
          return valor === true;
        }
      ),

    todasStoresPreservadas:
      Object.values(
        storesPreservadas
      ).every(
        function (valor) {
          return valor === true;
        }
      )
  };


  const aprovado =
    Object.values(validacoes)
      .every(
        function (valor) {
          return valor === true;
        }
      );


  const resultado = {
    etapa:
      "UX.20.1",

    auditoria:
      "CONFIGURACAO_PERSISTENTE_HISTORICO_OFFLINE",

    status:
      aprovado
        ? "APROVADO"
        : "REPROVADO",

    configuracao: {
      periodoAtual:
        valorOriginal,

      periodosPermitidos:
        [
          ...PERIODOS_HISTORICO_OFFLINE_UX201
        ],

      periodoPadrao:
        PERIODO_PADRAO_HISTORICO_UX201,

      chavePersistencia:
        CHAVE_HISTORICO_OFFLINE_UX201,

      escopo:
        "DISPOSITIVO_NAVEGADOR",

      limpezaExecutada:
        false
    },

    persistenciaTestada:
      resultadosPersistencia,

    clientesProtegidos:
      clientesProtegidos,

    interface: {
      selectEncontrado:
        Boolean(select),

      valorSelect:
        select?.value || "",

      opcoes:
        opcoesSelect,

      indicador:
        document.getElementById(
          "indicadorHistoricoOfflineUX201"
        )?.textContent || ""
    },

    stores: Object.fromEntries(
      storesAuditadas.map(
        function (nomeStore) {
          return [
            nomeStore,
            {
              antes:
                storesAntes[nomeStore]
                  .quantidade,

              depois:
                storesDepois[nomeStore]
                  .quantidade,

              preservada:
                storesPreservadas[
                  nomeStore
                ]
            }
          ];
        }
      )
    ),

    validacoes:
      validacoes,

    aprovado:
      aprovado
  };


  console.log(
    JSON.stringify(
      resultado,
      null,
      2
    )
  );


  if (!aprovado) {
    throw new Error(
      "UX.20.1 REPROVADA. Consulte as validações no console."
    );
  }


  console.log(
    "UX.20.1 — CONFIGURAÇÃO PERSISTENTE DO HISTÓRICO OFFLINE APROVADA."
  );

  return resultado;
}

/**
 * ============================================================
 * UX.20.2 — POLÍTICA SEGURA DE RETENÇÃO E LIMPEZA LOCAL
 * ============================================================
 *
 * Fluxo:
 *
 * 1. gerar plano em modo SIMULAÇÃO;
 * 2. armazenar token e assinaturas;
 * 3. exigir o mesmo token para a execução real;
 * 4. bloquear a execução se alguma store tiver mudado.
 *
 * Nenhuma limpeza é executada automaticamente.
 */

const STORES_RETENCAO_UX202 =
  Object.freeze([
    "TB_DIARIOS",
    "TB_DIARIO_ITENS",
    "TB_OCORRENCIAS",
    "TB_CLIMA",
    "TB_EVIDENCIAS",
    "TB_MEDICOES"
  ]);

const STORES_PRESERVADAS_UX202 =
  Object.freeze([
    "TB_LOTES_MEDICAO",
    "TB_SYNC_QUEUE",
    "TB_NOTIFICACOES"
  ]);

const STORES_AUDITADAS_UX202 =
  Object.freeze([
    ...STORES_RETENCAO_UX202,
    ...STORES_PRESERVADAS_UX202
  ]);


/**
 * Normalização textual.
 */
function textoUX202_(valor) {
  return String(
    valor === undefined ||
    valor === null
      ? ""
      : valor
  ).trim();
}


/**
 * Normalização sem acentos e em maiúsculas.
 */
function maiusculoUX202_(valor) {
  return textoUX202_(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}


/**
 * Converte uma data para YYYY-MM-DD.
 */
function normalizarDataUX202_(valor) {
  if (
    valor === undefined ||
    valor === null ||
    valor === ""
  ) {
    return "";
  }

  if (
    typeof valor === "number" &&
    Number.isFinite(valor)
  ) {
    const dataNumero =
      new Date(valor);

    if (
      !Number.isNaN(
        dataNumero.getTime()
      )
    ) {
      return dataNumero
        .toISOString()
        .slice(0, 10);
    }
  }

  const texto =
    String(valor).trim();

  const iso =
    texto.match(
      /^(\d{4})-(\d{2})-(\d{2})/
    );

  if (iso) {
    return (
      iso[1] +
      "-" +
      iso[2] +
      "-" +
      iso[3]
    );
  }

  const brasileira =
    texto.match(
      /^(\d{2})\/(\d{2})\/(\d{4})/
    );

  if (brasileira) {
    return (
      brasileira[3] +
      "-" +
      brasileira[2] +
      "-" +
      brasileira[1]
    );
  }

  const data =
    new Date(texto);

  if (
    !Number.isNaN(
      data.getTime()
    )
  ) {
    return data
      .toISOString()
      .slice(0, 10);
  }

  return "";
}


/**
 * Data local atual em YYYY-MM-DD.
 */
function obterDataLocalAtualUX202_() {
  const agora =
    new Date();

  const ano =
    agora.getFullYear();

  const mes =
    String(
      agora.getMonth() + 1
    ).padStart(2, "0");

  const dia =
    String(
      agora.getDate()
    ).padStart(2, "0");

  return (
    ano +
    "-" +
    mes +
    "-" +
    dia
  );
}


/**
 * Calcula o primeiro dia que deve permanecer.
 *
 * Exemplo:
 *
 * referência 13/07
 * período 30
 * início preservado 14/06
 */
function calcularDataCorteUX202_(
  periodoDias,
  dataReferencia = null
) {
  const referencia =
    normalizarDataUX202_(
      dataReferencia
    ) ||
    obterDataLocalAtualUX202_();

  const data =
    new Date(
      referencia +
      "T12:00:00"
    );

  data.setDate(
    data.getDate() -
    (
      Number(periodoDias) - 1
    )
  );

  const ano =
    data.getFullYear();

  const mes =
    String(
      data.getMonth() + 1
    ).padStart(2, "0");

  const dia =
    String(
      data.getDate()
    ).padStart(2, "0");

  return (
    ano +
    "-" +
    mes +
    "-" +
    dia
  );
}


/**
 * Retorna true quando a data está antes
 * do primeiro dia preservado.
 */
function dataForaRetencaoUX202_(
  dataRegistro,
  dataCorte
) {
  return (
    Boolean(dataRegistro) &&
    Boolean(dataCorte) &&
    dataRegistro < dataCorte
  );
}


/**
 * Obtém o primeiro campo preenchido.
 */
function primeiroCampoUX202_(
  registro,
  campos
) {
  for (const campo of campos) {
    const partes =
      String(campo).split(".");

    let valor =
      registro;

    for (const parte of partes) {
      valor =
        valor?.[parte];
    }

    if (
      valor !== undefined &&
      valor !== null &&
      valor !== ""
    ) {
      return valor;
    }
  }

  return "";
}


/**
 * ID principal por entidade.
 */
function obterIdRegistroUX202_(
  nomeStore,
  registro
) {
  const camposPorStore = {
    TB_DIARIOS: [
      "idDiario",
      "id"
    ],

    TB_DIARIO_ITENS: [
      "idItemDiario",
      "idDiarioItem",
      "idItem",
      "id"
    ],

    TB_OCORRENCIAS: [
      "idOcorrencia",
      "id"
    ],

    TB_CLIMA: [
      "idClima",
      "idRegistroClima",
      "id"
    ],

    TB_EVIDENCIAS: [
      "idEvidencia",
      "id"
    ],

    TB_MEDICOES: [
      "idItemMedicao",
      "idMedicao",
      "id"
    ]
  };

  return textoUX202_(
    primeiroCampoUX202_(
      registro,
      camposPorStore[nomeStore] ||
      ["id"]
    )
  );
}


/**
 * ID do Diário-pai de um item.
 */
function obterIdDiarioPaiUX202_(
  registro
) {
  return textoUX202_(
    primeiroCampoUX202_(
      registro,
      [
        "idDiario",
        "idDiarioObra",
        "idDiarioPai",
        "idReferencia",
        "ID_DIARIO"
      ]
    )
  );
}


/**
 * Identifica registro oficial de Medição.
 */
function registroEhMedicaoOficialUX202_(
  registro
) {
  return Boolean(
    registro?.registroOficial === true ||

    maiusculoUX202_(
      registro?.tipoRegistro
    ) ===
      "ITEM_MEDICAO_OFICIAL" ||

    textoUX202_(
      registro?.idMedicaoOficial
    ) !== "" ||

    textoUX202_(
      registro?.cabecalhoOficial
        ?.idMedicao
    ) !== ""
  );
}


/**
 * Obtém o ID do lote oficial armazenado
 * no registro local da Medição.
 */
function obterIdGrupoMedicaoUX202_(
  registro
) {
  return textoUX202_(
    primeiroCampoUX202_(
      registro,
      [
        "idMedicaoOficial",
        "cabecalhoOficial.idMedicao",
        "idMedicao"
      ]
    )
  );
}


/**
 * Obtém a data operacional usada pela retenção.
 */
function obterDataRegistroUX202_(
  nomeStore,
  registro,
  diarioPai = null
) {
  const camposPorStore = {
    TB_DIARIOS: [
      "data",
      "dataDiario",
      "dataRegistro",
      "dataCriacao",
      "criadoEm",
      "atualizadoEm"
    ],

    TB_DIARIO_ITENS: [
      "data",
      "dataProducao",
      "dataRegistro",
      "criadoEm",
      "atualizadoEm"
    ],

    TB_OCORRENCIAS: [
      "data",
      "dataOcorrencia",
      "dataRegistro",
      "dataCriacao",
      "criadoEm",
      "atualizadoEm"
    ],

    TB_CLIMA: [
      "data",
      "dataClima",
      "dataRegistro",
      "dataCriacao",
      "criadoEm",
      "atualizadoEm"
    ],

    TB_EVIDENCIAS: [
      "data",
      "dataEvidencia",
      "dataRegistro",
      "dataCriacao",
      "criadoEm",
      "atualizadoEm"
    ],

    TB_MEDICOES: [
      "cabecalhoOficial.periodoFim",
      "cabecalhoOficial.dataAprovacao",
      "cabecalhoOficial.dataCriacao",
      "periodoFim",
      "dataAprovacao",
      "dataCriacao",
      "criadoEm",
      "atualizadoEm"
    ]
  };

  const valor =
    primeiroCampoUX202_(
      registro,
      camposPorStore[nomeStore] ||
      []
    );

  const dataRegistro =
    normalizarDataUX202_(valor);

  if (dataRegistro) {
    return dataRegistro;
  }

  if (
    nomeStore ===
      "TB_DIARIO_ITENS" &&
    diarioPai
  ) {
    return obterDataRegistroUX202_(
      "TB_DIARIOS",
      diarioPai
    );
  }

  return "";
}


/**
 * Verifica exclusão lógica.
 */
function registroEhTombstoneUX202_(
  registro
) {
  if (
    registro?.tombstone === true ||
    registro?.deleted === true ||
    registro?.excluido === true
  ) {
    return true;
  }

  const operacao =
    maiusculoUX202_(
      primeiroCampoUX202_(
        registro,
        [
          "operacao",
          "acao",
          "tipoOperacao"
        ]
      )
    );

  return (
    operacao.includes("DELETE") ||
    operacao.includes("EXCLUIR") ||
    operacao.includes("REMOVER")
  );
}


/**
 * Status concluídos da fila.
 *
 * Status desconhecidos são tratados como ativos,
 * por segurança.
 */
function filaConcluidaUX202_(
  registro
) {
  const status =
    maiusculoUX202_(
      primeiroCampoUX202_(
        registro,
        [
          "statusSync",
          "status",
          "situacao"
        ]
      )
    );

  return [
    "SINCRONIZADO",
    "CONCLUIDO",
    "PROCESSADO",
    "ENVIADO",
    "SUCESSO",
    "OK",
    "CANCELADO"
  ].includes(status);
}


/**
 * Localiza referências ativas da fila.
 */
function localizarReferenciasAtivasFilaUX202_(
  fila,
  ids
) {
  const idsValidos =
    (
      Array.isArray(ids)
        ? ids
        : [ids]
    )
      .map(textoUX202_)
      .filter(Boolean);

  if (!idsValidos.length) {
    return [];
  }

  return (
    Array.isArray(fila)
      ? fila
      : []
  ).filter(
    function (registroFila) {
      if (
        filaConcluidaUX202_(
          registroFila
        )
      ) {
        return false;
      }

      let serializado = "";

      try {
        serializado =
          JSON.stringify(
            registroFila
          );

      } catch (erro) {
        /*
         * Registro não serializável:
         * preservação conservadora.
         */
        return true;
      }

      return idsValidos.some(
        function (id) {
          return serializado.includes(
            id
          );
        }
      );
    }
  );
}


/**
 * Status operacionais que ainda podem ser
 * editados pelo usuário.
 */
function registroEstaAbertoUX202_(
  registro
) {
  const status =
    maiusculoUX202_(
      primeiroCampoUX202_(
        registro,
        [
          "statusDiario",
          "statusOcorrencia",
          "statusItem",
          "statusMedicao",
          "status",
          "situacao"
        ]
      )
    );

  return [
    "ABERTO",
    "RASCUNHO",
    "EM ELABORACAO",
    "EM_ELABORACAO",
    "PENDENTE",
    "AGUARDANDO",
    "NAO FINALIZADO"
  ].includes(status);
}


/**
 * Verifica se há confirmação de que o registro
 * já está protegido no servidor.
 */
function registroConfirmadoNoServidorUX202_(
  registro
) {
  const origemReidratacao =
    maiusculoUX202_(
      registro?.origemReidratacao
    );

  if (
    origemReidratacao ===
    "SERVIDOR"
  ) {
    return true;
  }

  const statusSync =
    maiusculoUX202_(
      registro?.statusSync
    );

  return [
    "SINCRONIZADO",
    "CONCLUIDO",
    "PROCESSADO",
    "ENVIADO",
    "SUCESSO",
    "OK"
  ].includes(statusSync);
}


/**
 * Detecta arquivo ou binário local de Evidência.
 */
function evidenciaPossuiArquivoLocalUX202_(
  registro
) {
  const possuiBlob =
    typeof Blob !== "undefined" &&
    (
      registro?.blob instanceof Blob ||
      registro?.arquivoBlob instanceof Blob ||
      registro?.file instanceof Blob
    );

  return Boolean(
    textoUX202_(
      registro?.arquivoBase64
    ) ||

    possuiBlob ||

    registro?.arquivoLocal === true ||

    registro?.uploadPendente === true ||

    registro?.arquivoPendente === true ||

    registro?.fileHandle ||

    textoUX202_(
      registro?.caminhoLocal
    ) ||

    textoUX202_(
      registro?.urlLocal
    ) ||

    textoUX202_(
      registro?.objectUrl
    )
  );
}


/**
 * Avalia proteções comuns.
 */
function avaliarProtecoesRegistroUX202_({
  nomeStore,
  registro,
  fila,
  idsReferencia
}) {
  const motivos = [];

  if (
    registroEhTombstoneUX202_(
      registro
    )
  ) {
    motivos.push(
      "TOMBSTONE"
    );
  }

  if (
    registroEstaAbertoUX202_(
      registro
    )
  ) {
    motivos.push(
      "STATUS_OPERACIONAL_ABERTO"
    );
  }

  if (
    !registroConfirmadoNoServidorUX202_(
      registro
    )
  ) {
    motivos.push(
      "SEM_CONFIRMACAO_DO_SERVIDOR"
    );
  }

  const referenciasAtivas =
    localizarReferenciasAtivasFilaUX202_(
      fila,
      idsReferencia
    );

  if (
    referenciasAtivas.length
  ) {
    motivos.push(
      "PENDENCIA_ATIVA_NA_FILA"
    );
  }

  if (
    nomeStore ===
      "TB_EVIDENCIAS" &&
    evidenciaPossuiArquivoLocalUX202_(
      registro
    )
  ) {
    motivos.push(
      "ARQUIVO_LOCAL_PRESERVADO"
    );
  }

  if (
    registro?.preservarOffline === true ||
    registro?.fixadoOffline === true
  ) {
    motivos.push(
      "FIXADO_PARA_USO_OFFLINE"
    );
  }

  return {
    protegido:
      motivos.length > 0,

    motivos:
      motivos,

    referenciasAtivas:
      referenciasAtivas.length
  };
}


/**
 * Lê a keyPath real de cada store.
 */
async function obterKeyPathsUX202_(
  nomesStores
) {
  const db =
    await abrirBancoLocalSIGO();

  const resultado = {};

  for (const nomeStore of nomesStores) {
    const transacao =
      db.transaction(
        [nomeStore],
        "readonly"
      );

    const store =
      transacao.objectStore(
        nomeStore
      );

    resultado[nomeStore] =
      store.keyPath;
  }

  return resultado;
}


/**
 * Obtém a chave IndexedDB do registro.
 */
function obterChaveRegistroUX202_(
  registro,
  keyPath
) {
  if (
    Array.isArray(keyPath)
  ) {
    return keyPath.map(
      function (campo) {
        return registro?.[campo];
      }
    );
  }

  if (
    typeof keyPath === "string" &&
    keyPath
  ) {
    return registro?.[keyPath];
  }

  return undefined;
}


/**
 * Hash simples usado no token do plano.
 */
function gerarHashUX202_(valor) {
  const texto =
    String(valor);

  let hash =
    2166136261;

  for (
    let indice = 0;
    indice < texto.length;
    indice++
  ) {
    hash ^=
      texto.charCodeAt(indice);

    hash +=
      (
        hash << 1
      ) +
      (
        hash << 4
      ) +
      (
        hash << 7
      ) +
      (
        hash << 8
      ) +
      (
        hash << 24
      );
  }

  return (
    hash >>> 0
  )
    .toString(16)
    .padStart(8, "0");
}


/**
 * Captura conteúdo e assinatura das stores.
 */
async function capturarEstadoRetencaoUX202_() {
  const keyPaths =
    await obterKeyPathsUX202_(
      STORES_AUDITADAS_UX202
    );

  const resultado = {};

  for (
    const nomeStore of
    STORES_AUDITADAS_UX202
  ) {
    const registros =
      await lerStoreBrutaUX1997A_(
        nomeStore
      );

    resultado[nomeStore] = {
      registros:
        registros,

      quantidade:
        registros.length,

      assinatura:
        criarAssinaturaStoreMedicoesUX1994_(
          registros
        ),

      keyPath:
        keyPaths[nomeStore]
    };
  }

  return resultado;
}


/**
 * Assinaturas utilizadas para bloquear planos obsoletos.
 */
function extrairAssinaturasUX202_(
  estado
) {
  return Object.fromEntries(
    STORES_AUDITADAS_UX202.map(
      function (nomeStore) {
        return [
          nomeStore,
          estado[nomeStore]
            .assinatura
        ];
      }
    )
  );
}


/**
 * Compara dois conjuntos de assinaturas.
 */
function compararAssinaturasUX202_(
  esperado,
  atual
) {
  const divergencias = [];

  for (
    const nomeStore of
    STORES_AUDITADAS_UX202
  ) {
    if (
      esperado?.[nomeStore] !==
      atual?.[nomeStore]
    ) {
      divergencias.push({
        store:
          nomeStore,

        esperado:
          esperado?.[nomeStore] || "",

        atual:
          atual?.[nomeStore] || ""
      });
    }
  }

  return divergencias;
}


/**
 * Monta o plano protegido de retenção.
 */
async function montarPlanoRetencaoUX202_({
  idObra,
  periodoDias = null,
  dataReferencia = null
}) {
  const obra =
    textoUX202_(idObra);

  if (!obra) {
    throw new Error(
      "Informe o idObra para a política de retenção."
    );
  }

  let periodo;

  if (
    periodoDias === undefined ||
    periodoDias === null ||
    periodoDias === ""
  ) {
    periodo =
      obterPeriodoHistoricoOfflineUX201_();

  } else {
    periodo =
      normalizarPeriodoHistoricoUX201_(
        periodoDias,
        null
      );

    if (periodo === null) {
      throw new RangeError(
        "O período deve ser 15, 30, 60 ou 90 dias."
      );
    }
  }

  const referencia =
    normalizarDataUX202_(
      dataReferencia
    ) ||
    obterDataLocalAtualUX202_();

  const dataCorte =
    calcularDataCorteUX202_(
      periodo,
      referencia
    );

  const estado =
    await capturarEstadoRetencaoUX202_();

  const fila =
    estado
      .TB_SYNC_QUEUE
      .registros;

  const candidatos = [];

  const protegidos = [];

  const semData = [];

  const dentroPeriodo = {
    TB_DIARIOS:
      0,

    TB_DIARIO_ITENS:
      0,

    TB_OCORRENCIAS:
      0,

    TB_CLIMA:
      0,

    TB_EVIDENCIAS:
      0,

    TB_MEDICOES:
      0
  };

  const ignoradosOutraObra = {
    TB_DIARIOS:
      0,

    TB_DIARIO_ITENS:
      0,

    TB_OCORRENCIAS:
      0,

    TB_CLIMA:
      0,

    TB_EVIDENCIAS:
      0,

    TB_MEDICOES:
      0
  };


  function pertenceObra_(registro) {
    return (
      textoUX202_(
        registro?.idObra
      ) === obra
    );
  }


  function registrarCandidato_(
    nomeStore,
    registro,
    entidade,
    data,
    motivo
  ) {
    const keyPath =
      estado[nomeStore]
        .keyPath;

    const chave =
      obterChaveRegistroUX202_(
        registro,
        keyPath
      );

    if (
      chave === undefined ||
      chave === null ||
      (
        Array.isArray(chave) &&
        chave.some(
          function (parte) {
            return (
              parte === undefined ||
              parte === null
            );
          }
        )
      )
    ) {
      protegidos.push({
        store:
          nomeStore,

        id:
          obterIdRegistroUX202_(
            nomeStore,
            registro
          ),

        data:
          data,

        motivos: [
          "CHAVE_INDEXEDDB_INVALIDA"
        ]
      });

      return;
    }

    candidatos.push({
      store:
        nomeStore,

      entidade:
        entidade,

      id:
        obterIdRegistroUX202_(
          nomeStore,
          registro
        ),

      idObra:
        obra,

      data:
        data,

      motivo:
        motivo,

      chave:
        chave,

      chaveSerializada:
        JSON.stringify(chave),

      tombstone:
        false,

      registroOficial:
        nomeStore ===
          "TB_MEDICOES"
    });
  }


  function registrarProtegido_(
    nomeStore,
    registro,
    data,
    motivos
  ) {
    protegidos.push({
      store:
        nomeStore,

      id:
        obterIdRegistroUX202_(
          nomeStore,
          registro
      ),

      data:
        data,

      motivos:
        Array.from(
          new Set(motivos)
        )
    });
  }


  /*
   * ========================================================
   * DIÁRIOS E ITENS — LIMPEZA RELACIONAL
   * ========================================================
   */

  const diarios =
    estado
      .TB_DIARIOS
      .registros;

  const itens =
    estado
      .TB_DIARIO_ITENS
      .registros;

  const mapaDiarios =
    new Map();

  diarios.forEach(
    function (diario) {
      const id =
        obterIdRegistroUX202_(
          "TB_DIARIOS",
          diario
        );

      if (id) {
        mapaDiarios.set(
          id,
          diario
        );
      }
    }
  );

  const itensPorDiario =
    new Map();

  itens.forEach(
    function (item) {
      const idPai =
        obterIdDiarioPaiUX202_(
          item
        );

      if (!idPai) {
        return;
      }

      if (
        !itensPorDiario.has(
          idPai
        )
      ) {
        itensPorDiario.set(
          idPai,
          []
        );
      }

      itensPorDiario
        .get(idPai)
        .push(item);
    }
  );

  diarios.forEach(
    function (diario) {
      if (
        !pertenceObra_(diario)
      ) {
        ignoradosOutraObra
          .TB_DIARIOS++;

        return;
      }

      const idDiario =
        obterIdRegistroUX202_(
          "TB_DIARIOS",
          diario
        );

      const dataDiario =
        obterDataRegistroUX202_(
          "TB_DIARIOS",
          diario
        );

      const itensVinculados =
        itensPorDiario.get(
          idDiario
        ) || [];

      if (!dataDiario) {
        semData.push({
          store:
            "TB_DIARIOS",

          id:
            idDiario,

          motivo:
            "DIARIO_SEM_DATA"
        });

        return;
      }

      if (
        !dataForaRetencaoUX202_(
          dataDiario,
          dataCorte
        )
      ) {
        dentroPeriodo
          .TB_DIARIOS++;

        dentroPeriodo
          .TB_DIARIO_ITENS +=
            itensVinculados.length;

        return;
      }

      const idsGrupo = [
        idDiario,
        ...itensVinculados.map(
          function (item) {
            return obterIdRegistroUX202_(
              "TB_DIARIO_ITENS",
              item
            );
          }
        )
      ].filter(Boolean);

      const protecaoDiario =
        avaliarProtecoesRegistroUX202_({
          nomeStore:
            "TB_DIARIOS",

          registro:
            diario,

          fila:
            fila,

          idsReferencia:
            idsGrupo
        });

      const motivosGrupo = [
        ...protecaoDiario.motivos
      ];

      for (
        const item of
        itensVinculados
      ) {
        const dataItem =
          obterDataRegistroUX202_(
            "TB_DIARIO_ITENS",
            item,
            diario
          );

        if (
          dataItem &&
          !dataForaRetencaoUX202_(
            dataItem,
            dataCorte
          )
        ) {
          motivosGrupo.push(
            "ITEM_DENTRO_DO_PERIODO"
          );
        }

        const protecaoItem =
          avaliarProtecoesRegistroUX202_({
            nomeStore:
              "TB_DIARIO_ITENS",

            registro:
              item,

            fila:
              fila,

            idsReferencia:
              idsGrupo
          });

        motivosGrupo.push(
          ...protecaoItem.motivos
        );
      }

      const motivosUnicos =
        Array.from(
          new Set(motivosGrupo)
        );

      if (
        motivosUnicos.length
      ) {
        registrarProtegido_(
          "TB_DIARIOS",
          diario,
          dataDiario,
          motivosUnicos
        );

        return;
      }

      /*
       * Itens são incluídos antes do cabeçalho.
       */
      itensVinculados.forEach(
        function (item) {
          registrarCandidato_(
            "TB_DIARIO_ITENS",
            item,
            "ITEM_DIARIO",
            obterDataRegistroUX202_(
              "TB_DIARIO_ITENS",
              item,
              diario
            ),
            "DIARIO_PAI_FORA_DO_PERIODO"
          );
        }
      );

      registrarCandidato_(
        "TB_DIARIOS",
        diario,
        "DIARIO",
        dataDiario,
        "DIARIO_FORA_DO_PERIODO"
      );
    }
  );


  /*
   * Itens órfãos nunca são removidos automaticamente.
   */
  itens.forEach(
    function (item) {
      if (
        !pertenceObra_(item)
      ) {
        ignoradosOutraObra
          .TB_DIARIO_ITENS++;

        return;
      }

      const idPai =
        obterIdDiarioPaiUX202_(
          item
        );

      if (
        !idPai ||
        !mapaDiarios.has(idPai)
      ) {
        registrarProtegido_(
          "TB_DIARIO_ITENS",
          item,
          obterDataRegistroUX202_(
            "TB_DIARIO_ITENS",
            item
          ),
          [
            "ITEM_ORFAO_LOCAL"
          ]
        );
      }
    }
  );


  /*
   * ========================================================
   * ENTIDADES INDEPENDENTES
   * ========================================================
   */

  const storesIndependentes = [
    "TB_OCORRENCIAS",
    "TB_CLIMA",
    "TB_EVIDENCIAS"
  ];

  storesIndependentes.forEach(
    function (nomeStore) {
      estado[nomeStore]
        .registros
        .forEach(
          function (registro) {
            if (
              !pertenceObra_(
                registro
              )
            ) {
              ignoradosOutraObra[
                nomeStore
              ]++;

              return;
            }

            const data =
              obterDataRegistroUX202_(
                nomeStore,
                registro
              );

            if (!data) {
              semData.push({
                store:
                  nomeStore,

                id:
                  obterIdRegistroUX202_(
                    nomeStore,
                    registro
                  ),

                motivo:
                  "REGISTRO_SEM_DATA"
              });

              return;
            }

            if (
              !dataForaRetencaoUX202_(
                data,
                dataCorte
              )
            ) {
              dentroPeriodo[
                nomeStore
              ]++;

              return;
            }

            const id =
              obterIdRegistroUX202_(
                nomeStore,
                registro
              );

            const protecao =
              avaliarProtecoesRegistroUX202_({
                nomeStore:
                  nomeStore,

                registro:
                  registro,

                fila:
                  fila,

                idsReferencia:
                  [id]
              });

            if (protecao.protegido) {
              registrarProtegido_(
                nomeStore,
                registro,
                data,
                protecao.motivos
              );

              return;
            }

            registrarCandidato_(
              nomeStore,
              registro,
              nomeStore.replace(
                "TB_",
                ""
              ),
              data,
              "REGISTRO_FORA_DO_PERIODO"
            );
          }
        );
    }
  );


  /*
   * ========================================================
   * MEDIÇÕES — SOMENTE REGISTROS OFICIAIS
   * ========================================================
   */

  const medicoes =
    estado
      .TB_MEDICOES
      .registros;

  const gruposMedicao =
    new Map();

  let medicoesOperacionaisPreservadas =
    0;

  medicoes.forEach(
    function (registro) {
      if (
        !pertenceObra_(registro)
      ) {
        ignoradosOutraObra
          .TB_MEDICOES++;

        return;
      }

      if (
        !registroEhMedicaoOficialUX202_(
          registro
        )
      ) {
        medicoesOperacionaisPreservadas++;

        return;
      }

      const idGrupo =
        obterIdGrupoMedicaoUX202_(
          registro
        ) ||
        obterIdRegistroUX202_(
          "TB_MEDICOES",
          registro
        );

      if (
        !gruposMedicao.has(
          idGrupo
        )
      ) {
        gruposMedicao.set(
          idGrupo,
          []
        );
      }

      gruposMedicao
        .get(idGrupo)
        .push(registro);
    }
  );

  gruposMedicao.forEach(
    function (
      registrosGrupo,
      idGrupo
    ) {
      const datas =
        registrosGrupo
          .map(
            function (registro) {
              return obterDataRegistroUX202_(
                "TB_MEDICOES",
                registro
              );
            }
          )
          .filter(Boolean);

      if (
        datas.length !==
        registrosGrupo.length
      ) {
        registrosGrupo.forEach(
          function (registro) {
            registrarProtegido_(
              "TB_MEDICOES",
              registro,
              obterDataRegistroUX202_(
                "TB_MEDICOES",
                registro
              ),
              [
                "MEDICAO_OFICIAL_SEM_DATA"
              ]
            );
          }
        );

        return;
      }

      const existeDentroPeriodo =
        datas.some(
          function (data) {
            return !dataForaRetencaoUX202_(
              data,
              dataCorte
            );
          }
        );

      if (existeDentroPeriodo) {
        dentroPeriodo
          .TB_MEDICOES +=
            registrosGrupo.length;

        return;
      }

      const idsGrupo = [
        idGrupo,
        ...registrosGrupo.map(
          function (registro) {
            return obterIdRegistroUX202_(
              "TB_MEDICOES",
              registro
            );
          }
        )
      ].filter(Boolean);

      const motivosGrupo = [];

      registrosGrupo.forEach(
        function (registro) {
          const protecao =
            avaliarProtecoesRegistroUX202_({
              nomeStore:
                "TB_MEDICOES",

              registro:
                registro,

              fila:
                fila,

              idsReferencia:
                idsGrupo
            });

          motivosGrupo.push(
            ...protecao.motivos
          );
        }
      );

      const motivosUnicos =
        Array.from(
          new Set(motivosGrupo)
        );

      if (
        motivosUnicos.length
      ) {
        registrosGrupo.forEach(
          function (registro) {
            registrarProtegido_(
              "TB_MEDICOES",
              registro,
              obterDataRegistroUX202_(
                "TB_MEDICOES",
                registro
              ),
              motivosUnicos
            );
          }
        );

        return;
      }

      registrosGrupo.forEach(
        function (registro) {
          registrarCandidato_(
            "TB_MEDICOES",
            registro,
            "ITEM_MEDICAO_OFICIAL",
            obterDataRegistroUX202_(
              "TB_MEDICOES",
              registro
            ),
            "MEDICAO_OFICIAL_FORA_DO_PERIODO"
          );
        }
      );
    }
  );


  /*
   * ========================================================
   * NORMALIZAÇÃO DO PLANO
   * ========================================================
   */

  const prioridades = {
    TB_DIARIO_ITENS:
      1,

    TB_DIARIOS:
      2,

    TB_OCORRENCIAS:
      3,

    TB_CLIMA:
      4,

    TB_EVIDENCIAS:
      5,

    TB_MEDICOES:
      6
  };

  candidatos.sort(
    function (a, b) {
      return (
        prioridades[a.store] -
        prioridades[b.store]
      );
    }
  );

  const duplicidadesPlano = [];

  const chavesPlano =
    new Set();

  candidatos.forEach(
    function (candidato) {
      const chaveUnica =
        candidato.store +
        "::" +
        candidato.chaveSerializada;

      if (
        chavesPlano.has(
          chaveUnica
        )
      ) {
        duplicidadesPlano.push(
          chaveUnica
        );
      }

      chavesPlano.add(
        chaveUnica
      );
    }
  );

  const porStore =
    Object.fromEntries(
      STORES_RETENCAO_UX202.map(
        function (nomeStore) {
          return [
            nomeStore,
            candidatos.filter(
              function (registro) {
                return (
                  registro.store ===
                  nomeStore
                );
              }
            ).length
          ];
        }
      )
    );

  const assinaturas =
    extrairAssinaturasUX202_(
      estado
    );

  const baseToken = {
    idObra:
      obra,

    periodoDias:
      periodo,

    dataReferencia:
      referencia,

    dataCorte:
      dataCorte,

    assinaturas:
      assinaturas,

    candidatos:
      candidatos.map(
        function (registro) {
          return {
            store:
              registro.store,

            chave:
              registro.chaveSerializada
          };
        }
      )
  };

  const tokenPlano =
    "UX202-" +
    gerarHashUX202_(
      JSON.stringify(baseToken)
    );

  return {
    idObra:
      obra,

    periodoDias:
      periodo,

    dataReferencia:
      referencia,

    dataCorte:
      dataCorte,

    estado:
      estado,

    assinaturas:
      assinaturas,

    candidatos:
      candidatos,

    protegidos:
      protegidos,

    semData:
      semData,

    dentroPeriodo:
      dentroPeriodo,

    ignoradosOutraObra:
      ignoradosOutraObra,

    medicoesOperacionaisPreservadas:
      medicoesOperacionaisPreservadas,

    duplicidadesPlano:
      duplicidadesPlano,

    porStore:
      porStore,

    totalExcluir:
      candidatos.length,

    tokenPlano:
      tokenPlano
  };
}


/**
 * ============================================================
 * SIMULAÇÃO
 * ============================================================
 */
async function simularRetencaoLocalUX202_({
  idObra,
  periodoDias = null,
  dataReferencia = null
} = {}) {
  console.log(
    "[UX.20.2] Iniciando simulação da retenção local..."
  );

  const plano =
    await montarPlanoRetencaoUX202_({
      idObra:
        idObra,

      periodoDias:
        periodoDias,

      dataReferencia:
        dataReferencia
    });

  const estadoDepois =
    await capturarEstadoRetencaoUX202_();

  const assinaturasDepois =
    extrairAssinaturasUX202_(
      estadoDepois
    );

  const storesAlteradas =
    compararAssinaturasUX202_(
      plano.assinaturas,
      assinaturasDepois
    );

  const validacoes = {
    modoSimulacao:
      true,

    periodoPermitido:
      [
        15,
        30,
        60,
        90
      ].includes(
        plano.periodoDias
      ),

    tokenGerado:
      Boolean(
        plano.tokenPlano
      ),

    nenhumaGravacaoExecutada:
      true,

    nenhumaStoreAlterada:
      storesAlteradas.length === 0,

    nenhumaDuplicidadeNoPlano:
      plano.duplicidadesPlano.length ===
      0,

    filaNaoEhCandidata:
      plano.porStore
        .TB_SYNC_QUEUE ===
      undefined,

    lotesNaoSaoCandidatos:
      plano.porStore
        .TB_LOTES_MEDICAO ===
      undefined,

    notificacoesNaoSaoCandidatas:
      plano.porStore
        .TB_NOTIFICACOES ===
      undefined,

    medicoesOperacionaisPreservadas:
      plano
        .medicoesOperacionaisPreservadas >=
      0,

    nenhumTombstoneCandidato:
      plano.candidatos.every(
        function (registro) {
          return (
            registro.tombstone ===
            false
          );
        }
      )
  };

  const aprovado =
    Object.values(validacoes)
      .every(
        function (valor) {
          return valor === true;
        }
      );

  window.SIGO_UX202 =
    window.SIGO_UX202 || {};

  window.SIGO_UX202
    .ultimaSimulacao = {
      tokenPlano:
        plano.tokenPlano,

      idObra:
        plano.idObra,

      periodoDias:
        plano.periodoDias,

      dataReferencia:
        plano.dataReferencia,

      dataCorte:
        plano.dataCorte,

      assinaturas:
        plano.assinaturas,

      candidatos:
        plano.candidatos,

      geradoEm:
        new Date().toISOString()
    };

  const resultado = {
    etapa:
      "UX.20.2",

    operacao:
      "POLITICA_RETENCAO_LOCAL",

    modo:
      "SIMULACAO",

    status:
      aprovado
        ? "APROVADO"
        : "REPROVADO",

    idObra:
      plano.idObra,

    periodoDias:
      plano.periodoDias,

    dataReferencia:
      plano.dataReferencia,

    dataCorte:
      plano.dataCorte,

    regra:
      "PRESERVAR_DATA_MAIOR_OU_IGUAL_A_DATA_CORTE",

    tokenPlano:
      plano.tokenPlano,

    totalExcluir:
      plano.totalExcluir,

    porStore:
      plano.porStore,

    dentroPeriodo:
      plano.dentroPeriodo,

    protegidosForaPeriodo: {
      total:
        plano.protegidos.length,

      registros:
        plano.protegidos
    },

    registrosSemData: {
      total:
        plano.semData.length,

      registros:
        plano.semData
    },

    medicoesOperacionaisPreservadas:
      plano
        .medicoesOperacionaisPreservadas,

    candidatos:
      plano.candidatos,

    storesPreservadas: {
      TB_LOTES_MEDICAO:
        plano.estado
          .TB_LOTES_MEDICAO
          .quantidade,

      TB_SYNC_QUEUE:
        plano.estado
          .TB_SYNC_QUEUE
          .quantidade,

      TB_NOTIFICACOES:
        plano.estado
          .TB_NOTIFICACOES
          .quantidade
    },

    storesAlteradas:
      storesAlteradas,

    gravacoesPlanejadas:
      plano.totalExcluir,

    gravacoesExecutadas:
      0,

    validacoes:
      validacoes,

    aprovado:
      aprovado
  };

  console.log(
    JSON.stringify(
      resultado,
      null,
      2
    )
  );

  if (!aprovado) {
    throw new Error(
      "UX.20.2 REPROVADA NA SIMULAÇÃO. Consulte as validações."
    );
  }

  console.log(
    "UX.20.2 — SIMULAÇÃO DA RETENÇÃO LOCAL APROVADA."
  );

  return resultado;
}


/**
 * Remove as chaves planejadas em uma única
 * transação IndexedDB.
 */
async function excluirPlanoRetencaoUX202_(
  candidatos
) {
  if (
    !Array.isArray(candidatos) ||
    !candidatos.length
  ) {
    return {
      total:
        0,

      porStore:
        {}
    };
  }

  const stores =
    Array.from(
      new Set(
        candidatos.map(
          function (registro) {
            return registro.store;
          }
        )
      )
    );

  const db =
    await abrirBancoLocalSIGO();

  await new Promise(
    function (resolve, reject) {
      const transacao =
        db.transaction(
          stores,
          "readwrite"
        );

      candidatos.forEach(
        function (registro) {
          transacao
            .objectStore(
              registro.store
            )
            .delete(
              registro.chave
            );
        }
      );

      transacao.oncomplete =
        function () {
          resolve();
        };

      transacao.onerror =
        function () {
          reject(
            transacao.error ||
            new Error(
              "Falha na limpeza local."
            )
          );
        };

      transacao.onabort =
        function () {
          reject(
            transacao.error ||
            new Error(
              "A limpeza local foi abortada."
            )
          );
        };
    }
  );

  return {
    total:
      candidatos.length,

    porStore:
      Object.fromEntries(
        stores.map(
          function (nomeStore) {
            return [
              nomeStore,
              candidatos.filter(
                function (registro) {
                  return (
                    registro.store ===
                    nomeStore
                  );
                }
              ).length
            ];
          }
        )
      )
  };
}


/**
 * Atualiza caches e interfaces após a limpeza real.
 */
async function finalizarRetencaoLocalUX202_(
  idObra,
  storesAlteradas
) {
  for (
    const nomeStore of
    storesAlteradas
  ) {
    if (
      typeof SIGODataCache !==
        "undefined" &&
      SIGODataCache &&
      typeof SIGODataCache.invalidate ===
        "function"
    ) {
      SIGODataCache.invalidate(
        nomeStore
      );
    }

    if (
      typeof invalidarCacheObraSIGO_ ===
        "function"
    ) {
      await Promise.resolve(
        invalidarCacheObraSIGO_(
          nomeStore,
          idObra
        )
      );
    }

    if (
      typeof SIGODataBinding !==
        "undefined" &&
      SIGODataBinding &&
      typeof SIGODataBinding.notify ===
        "function"
    ) {
      try {
        await SIGODataBinding.notify(
          nomeStore,
          {
            acao:
              "RETENCAO_LOCAL",

            store:
              nomeStore,

            chave:
              null,

            registro:
              null,

            idObra:
              idObra,

            origem:
              "UX.20.2",

            quantidade:
              1
          }
        );

      } catch (erro) {
        console.warn(
          "[UX.20.2] DataBinding não atualizado:",
          nomeStore,
          erro
        );
      }
    }
  }
}


/**
 * ============================================================
 * EXECUÇÃO REAL
 * ============================================================
 *
 * Exige token produzido pela simulação.
 */
async function executarRetencaoLocalUX202_(
  tokenPlano
) {
  console.log(
    "[UX.20.2] Validando plano para execução real..."
  );

  const simulacao =
    window.SIGO_UX202
      ?.ultimaSimulacao;

  if (!simulacao) {
    throw new Error(
      "Nenhuma simulação válida foi encontrada."
    );
  }

  if (
    textoUX202_(tokenPlano) !==
    simulacao.tokenPlano
  ) {
    throw new Error(
      "Token do plano inválido. Execute uma nova simulação."
    );
  }

  const estadoAntes =
    await capturarEstadoRetencaoUX202_();

  const assinaturasAntes =
    extrairAssinaturasUX202_(
      estadoAntes
    );

  const divergenciasAntes =
    compararAssinaturasUX202_(
      simulacao.assinaturas,
      assinaturasAntes
    );

  if (
    divergenciasAntes.length
  ) {
    console.error(
      "[UX.20.2] Plano obsoleto:",
      divergenciasAntes
    );

    throw new Error(
      "As stores mudaram após a simulação. Gere um novo plano."
    );
  }

  const assinaturaFilaAntes =
    estadoAntes
      .TB_SYNC_QUEUE
      .assinatura;

  const assinaturaLotesAntes =
    estadoAntes
      .TB_LOTES_MEDICAO
      .assinatura;

  const assinaturaNotificacoesAntes =
    estadoAntes
      .TB_NOTIFICACOES
      .assinatura;

  const exclusao =
    await excluirPlanoRetencaoUX202_(
      simulacao.candidatos
    );

  const nomesAlterados =
    Object.keys(
      exclusao.porStore
    );

  await finalizarRetencaoLocalUX202_(
    simulacao.idObra,
    nomesAlterados
  );

  const estadoDepois =
    await capturarEstadoRetencaoUX202_();

  const candidatosAindaExistentes = [];

  for (
    const candidato of
    simulacao.candidatos
  ) {
    const storeDepois =
      estadoDepois[
        candidato.store
      ];

    const keyPath =
      storeDepois.keyPath;

    const aindaExiste =
      storeDepois.registros.some(
        function (registro) {
          const chave =
            obterChaveRegistroUX202_(
              registro,
              keyPath
            );

          return (
            JSON.stringify(chave) ===
            candidato.chaveSerializada
          );
        }
      );

    if (aindaExiste) {
      candidatosAindaExistentes.push(
        candidato
      );
    }
  }

  const filaPreservada =
    assinaturaFilaAntes ===
    estadoDepois
      .TB_SYNC_QUEUE
      .assinatura;

  const lotesPreservados =
    assinaturaLotesAntes ===
    estadoDepois
      .TB_LOTES_MEDICAO
      .assinatura;

  const notificacoesPreservadas =
    assinaturaNotificacoesAntes ===
    estadoDepois
      .TB_NOTIFICACOES
      .assinatura;

  const validacoes = {
    tokenValido:
      true,

    planoNaoEstavaObsoleto:
      divergenciasAntes.length === 0,

    totalExecutadoConformePlano:
      exclusao.total ===
      simulacao.candidatos.length,

    nenhumCandidatoPermaneceu:
      candidatosAindaExistentes.length ===
      0,

    filaPreservada:
      filaPreservada,

    lotesPreservados:
      lotesPreservados,

    notificacoesPreservadas:
      notificacoesPreservadas
  };

  const aprovado =
    Object.values(validacoes)
      .every(
        function (valor) {
          return valor === true;
        }
      );

  const resultado = {
    etapa:
      "UX.20.2",

    operacao:
      "POLITICA_RETENCAO_LOCAL",

    modo:
      "REAL",

    status:
      aprovado
        ? "APROVADO"
        : "REPROVADO",

    idObra:
      simulacao.idObra,

    periodoDias:
      simulacao.periodoDias,

    dataReferencia:
      simulacao.dataReferencia,

    dataCorte:
      simulacao.dataCorte,

    tokenPlano:
      simulacao.tokenPlano,

    gravacoesPlanejadas:
      simulacao.candidatos.length,

    gravacoesExecutadas:
      exclusao.total,

    removidosPorStore:
      exclusao.porStore,

    candidatosAindaExistentes:
      candidatosAindaExistentes,

    storesPreservadas: {
      TB_SYNC_QUEUE: {
        antes:
          estadoAntes
            .TB_SYNC_QUEUE
            .quantidade,

        depois:
          estadoDepois
            .TB_SYNC_QUEUE
            .quantidade,

        preservada:
          filaPreservada
      },

      TB_LOTES_MEDICAO: {
        antes:
          estadoAntes
            .TB_LOTES_MEDICAO
            .quantidade,

        depois:
          estadoDepois
            .TB_LOTES_MEDICAO
            .quantidade,

        preservada:
          lotesPreservados
      },

      TB_NOTIFICACOES: {
        antes:
          estadoAntes
            .TB_NOTIFICACOES
            .quantidade,

        depois:
          estadoDepois
            .TB_NOTIFICACOES
            .quantidade,

        preservada:
          notificacoesPreservadas
      }
    },

    validacoes:
      validacoes,

    aprovado:
      aprovado
  };

  console.log(
    JSON.stringify(
      resultado,
      null,
      2
    )
  );

  if (!aprovado) {
    throw new Error(
      "UX.20.2 REPROVADA NA EXECUÇÃO REAL."
    );
  }

  window.SIGO_UX202
    .ultimaExecucao =
      resultado;

  window.SIGO_UX202
    .ultimaSimulacao =
      null;

  console.log(
    "UX.20.2 — RETENÇÃO LOCAL EXECUTADA COM SEGURANÇA."
  );

  return resultado;
}


/**
 * Auditoria específica da simulação.
 */
async function auditarSimulacaoRetencaoLocalUX202_({
  idObra,
  periodoDias = null,
  dataReferencia = null
} = {}) {
  const estadoAntes =
    await capturarEstadoRetencaoUX202_();

  const resultado =
    await simularRetencaoLocalUX202_({
      idObra:
        idObra,

      periodoDias:
        periodoDias,

      dataReferencia:
        dataReferencia
    });

  const estadoDepois =
    await capturarEstadoRetencaoUX202_();

  const alteradas =
    compararAssinaturasUX202_(
      extrairAssinaturasUX202_(
        estadoAntes
      ),
      extrairAssinaturasUX202_(
        estadoDepois
      )
    );

  const validacoesAuditoria = {
    simulacaoAprovada:
      resultado.aprovado === true,

    nenhumaStoreAlterada:
      alteradas.length === 0,

    nenhumaGravacaoExecutada:
      resultado
        .gravacoesExecutadas === 0,

    filaPermaneceuPreservada:
      estadoAntes
        .TB_SYNC_QUEUE
        .assinatura ===
      estadoDepois
        .TB_SYNC_QUEUE
        .assinatura,

    lotesPermaneceramPreservados:
      estadoAntes
        .TB_LOTES_MEDICAO
        .assinatura ===
      estadoDepois
        .TB_LOTES_MEDICAO
        .assinatura,

    notificacoesPermaneceramPreservadas:
      estadoAntes
        .TB_NOTIFICACOES
        .assinatura ===
      estadoDepois
        .TB_NOTIFICACOES
        .assinatura,

    cincoMedicoesOperacionaisPreservadas:
      resultado
        .medicoesOperacionaisPreservadas ===
      5
  };

  const aprovado =
    Object.values(
      validacoesAuditoria
    ).every(
      function (valor) {
        return valor === true;
      }
    );

  const auditoria = {
    etapa:
      "UX.20.2",

    auditoria:
      "SIMULACAO_POLITICA_RETENCAO_LOCAL",

    status:
      aprovado
        ? "APROVADO"
        : "REPROVADO",

    simulacao:
      resultado,

    storesAlteradas:
      alteradas,

    validacoes:
      validacoesAuditoria,

    aprovado:
      aprovado
  };

  console.log(
    JSON.stringify(
      auditoria,
      null,
      2
    )
  );

  if (!aprovado) {
    throw new Error(
      "UX.20.2 REPROVADA NA AUDITORIA DA SIMULAÇÃO."
    );
  }

  console.log(
    "UX.20.2 — AUDITORIA DA SIMULAÇÃO APROVADA."
  );

  return auditoria;
}

/**
 * ============================================================
 * UX.20.2A — TESTE CONTROLADO DE EXCLUSÃO EFETIVA
 * ============================================================
 *
 * Cria temporariamente um único registro em TB_CLIMA,
 * com data anterior ao corte configurado.
 *
 * O teste:
 *
 * 1. confirma que não há candidatos reais;
 * 2. insere um registro temporário diretamente;
 * 3. executa a simulação da UX.20.2;
 * 4. exige exatamente um candidato;
 * 5. executa a retenção real;
 * 6. confirma a remoção;
 * 7. compara todas as stores com o estado original.
 *
 * Nenhuma entrada é criada na TB_SYNC_QUEUE.
 */


/**
 * Retorna o dia imediatamente anterior.
 */
function obterDiaAnteriorUX202A_(
  dataIso
) {
  const data =
    new Date(
      dataIso + "T12:00:00"
    );

  if (
    Number.isNaN(
      data.getTime()
    )
  ) {
    throw new Error(
      "Data inválida para o teste controlado: " +
      dataIso
    );
  }

  data.setDate(
    data.getDate() - 1
  );

  const ano =
    data.getFullYear();

  const mes =
    String(
      data.getMonth() + 1
    ).padStart(2, "0");

  const dia =
    String(
      data.getDate()
    ).padStart(2, "0");

  return (
    ano +
    "-" +
    mes +
    "-" +
    dia
  );
}


/**
 * Gera um ID exclusivo para o registro temporário.
 */
function gerarIdTesteRetencaoUX202A_() {
  const sufixo =
    typeof crypto !== "undefined" &&
    typeof crypto.randomUUID ===
      "function"
      ? crypto
          .randomUUID()
          .slice(0, 8)
      : Math.random()
          .toString(16)
          .slice(2, 10);

  return (
    "CLM-UX202A-" +
    Date.now() +
    "-" +
    sufixo
  );
}


/**
 * Grava diretamente no IndexedDB.
 *
 * Não usa os métodos normais de criação para não
 * produzir operação na fila de sincronização.
 */
async function gravarRegistroDiretoUX202A_(
  nomeStore,
  registro
) {
  const db =
    await abrirBancoLocalSIGO();

  await new Promise(
    function (resolve, reject) {
      const transacao =
        db.transaction(
          [nomeStore],
          "readwrite"
        );

      const store =
        transacao.objectStore(
          nomeStore
        );

      store.put(
        registro
      );

      transacao.oncomplete =
        function () {
          resolve();
        };

      transacao.onerror =
        function () {
          reject(
            transacao.error ||
            new Error(
              "Falha ao inserir o registro temporário."
            )
          );
        };

      transacao.onabort =
        function () {
          reject(
            transacao.error ||
            new Error(
              "A inserção temporária foi abortada."
            )
          );
        };
    }
  );
}


/**
 * Exclui diretamente uma chave.
 *
 * Utilizada como limpeza emergencial caso o teste
 * seja interrompido antes da execução da retenção.
 */
async function excluirRegistroDiretoUX202A_(
  nomeStore,
  chave
) {
  const db =
    await abrirBancoLocalSIGO();

  await new Promise(
    function (resolve, reject) {
      const transacao =
        db.transaction(
          [nomeStore],
          "readwrite"
        );

      const store =
        transacao.objectStore(
          nomeStore
        );

      store.delete(
        chave
      );

      transacao.oncomplete =
        function () {
          resolve();
        };

      transacao.onerror =
        function () {
          reject(
            transacao.error ||
            new Error(
              "Falha ao remover o registro temporário."
            )
          );
        };

      transacao.onabort =
        function () {
          reject(
            transacao.error ||
            new Error(
              "A remoção temporária foi abortada."
            )
          );
        };
    }
  );
}


/**
 * Invalida os caches da store usada no teste.
 */
async function invalidarCacheTesteUX202A_(
  nomeStore,
  idObra
) {
  if (
    typeof SIGODataCache !==
      "undefined" &&
    SIGODataCache &&
    typeof SIGODataCache.invalidate ===
      "function"
  ) {
    SIGODataCache.invalidate(
      nomeStore
    );
  }

  if (
    typeof invalidarCacheObraSIGO_ ===
      "function"
  ) {
    await Promise.resolve(
      invalidarCacheObraSIGO_(
        nomeStore,
        idObra
      )
    );
  }
}


/**
 * Pesquisa uma referência ao ID na fila.
 */
function localizarReferenciasTesteFilaUX202A_(
  fila,
  idTeste
) {
  return (
    Array.isArray(fila)
      ? fila
      : []
  ).filter(
    function (registro) {
      try {
        return JSON.stringify(
          registro
        ).includes(
          idTeste
        );

      } catch (erro) {
        return false;
      }
    }
  );
}


/**
 * ============================================================
 * TESTE PRINCIPAL
 * ============================================================
 */
async function testarExclusaoEfetivaRetencaoUX202A_() {
  console.log(
    "[UX.20.2A] Iniciando teste controlado de exclusão efetiva..."
  );

  const nomeStore =
    "TB_CLIMA";

  const idObra =
    "OBR002";

  const periodoDias =
    obterPeriodoHistoricoOfflineUX201_();

  const dataReferencia =
    obterDataLocalAtualUX202_();

  const dataCorte =
    calcularDataCorteUX202_(
      periodoDias,
      dataReferencia
    );

  const dataRegistroTeste =
    obterDiaAnteriorUX202A_(
      dataCorte
    );

  const idTeste =
    gerarIdTesteRetencaoUX202A_();

  let chaveTeste =
    null;

  let registroInserido =
    false;

  let simulacao =
    null;

  let execucao =
    null;


  /*
   * ========================================================
   * ESTADO ORIGINAL
   * ========================================================
   */

  const estadoOriginal =
    await capturarEstadoRetencaoUX202_();

  const assinaturasOriginais =
    extrairAssinaturasUX202_(
      estadoOriginal
    );

  const planoOriginal =
    await montarPlanoRetencaoUX202_({
      idObra:
        idObra,

      periodoDias:
        periodoDias,

      dataReferencia:
        dataReferencia
    });


  /*
   * Não permite que o teste seja realizado se houver
   * candidatos reais.
   */
  if (
    planoOriginal.totalExcluir !== 0
  ) {
    throw new Error(
      "O teste foi bloqueado porque já existem " +
      planoOriginal.totalExcluir +
      " candidatos reais à retenção."
    );
  }


  const keyPath =
    estadoOriginal[
      nomeStore
    ].keyPath;

  if (
    typeof keyPath !== "string" ||
    !keyPath
  ) {
    throw new Error(
      "A TB_CLIMA não possui uma keyPath simples válida."
    );
  }


  const registroTeste = {
    idClima:
      idTeste,

    idRegistroClima:
      idTeste,

    idObra:
      idObra,

    data:
      dataRegistroTeste,

    dataClima:
      dataRegistroTeste,

    periodo:
      "TESTE_CONTROLADO_UX202A",

    condicao:
      "TESTE DE RETENÇÃO",

    clima:
      "TESTE DE RETENÇÃO",

    turno:
      "TESTE",

    temperatura:
      "",

    observacoes:
      "Registro temporário criado exclusivamente pela UX.20.2A.",

    status:
      "REGISTRADO",

    statusSync:
      "SINCRONIZADO",

    origem:
      "TESTE_CONTROLADO_UX202A",

    origemReidratacao:
      "SERVIDOR",

    dataSync:
      new Date().toISOString(),

    criadoEm:
      dataRegistroTeste +
      "T12:00:00.000Z",

    atualizadoEm:
      dataRegistroTeste +
      "T12:00:00.000Z",

    registroTemporario:
      true,

    ux202a:
      true
  };

  /*
   * Garante que a chave real da store seja preenchida.
   */
  registroTeste[
    keyPath
  ] =
    idTeste;

  chaveTeste =
    registroTeste[
      keyPath
    ];


  try {
    /*
     * ======================================================
     * INSERÇÃO CONTROLADA
     * ======================================================
     */

    await gravarRegistroDiretoUX202A_(
      nomeStore,
      registroTeste
    );

    registroInserido =
      true;

    await invalidarCacheTesteUX202A_(
      nomeStore,
      idObra
    );


    const estadoComTeste =
      await capturarEstadoRetencaoUX202_();

    const registroEncontradoAposInsercao =
      estadoComTeste
        .TB_CLIMA
        .registros
        .find(
          function (registro) {
            return (
              textoUX202_(
                registro?.idClima
              ) === idTeste
            );
          }
        ) || null;


    if (
      !registroEncontradoAposInsercao
    ) {
      throw new Error(
        "O registro controlado não foi encontrado após a inserção."
      );
    }


    if (
      estadoComTeste
        .TB_CLIMA
        .quantidade !==
      estadoOriginal
        .TB_CLIMA
        .quantidade + 1
    ) {
      throw new Error(
        "A quantidade da TB_CLIMA não aumentou exatamente em uma unidade."
      );
    }


    const referenciasFilaComTeste =
      localizarReferenciasTesteFilaUX202A_(
        estadoComTeste
          .TB_SYNC_QUEUE
          .registros,
        idTeste
      );


    if (
      referenciasFilaComTeste.length !== 0
    ) {
      throw new Error(
        "O registro temporário apareceu indevidamente na fila."
      );
    }


    /*
     * ======================================================
     * SIMULAÇÃO COM UM CANDIDATO
     * ======================================================
     */

    simulacao =
      await simularRetencaoLocalUX202_({
        idObra:
          idObra,

        periodoDias:
          periodoDias,

        dataReferencia:
          dataReferencia
      });


    const candidatoTeste =
      simulacao.candidatos.find(
        function (candidato) {
          return (
            candidato.store ===
              nomeStore &&
            candidato.id ===
              idTeste
          );
        }
      ) || null;


    const candidatosOutrasStores =
      Object.entries(
        simulacao.porStore
      )
        .filter(
          function ([store]) {
            return store !==
              nomeStore;
          }
        )
        .reduce(
          function (
            total,
            [, quantidade]
          ) {
            return (
              total +
              Number(
                quantidade || 0
              )
            );
          },
          0
        );


    const validacoesSimulacao = {
      simulacaoAprovada:
        simulacao.aprovado === true,

      totalExcluir1:
        simulacao.totalExcluir === 1,

      climaExcluir1:
        simulacao
          .porStore
          .TB_CLIMA === 1,

      outrasStoresExcluir0:
        candidatosOutrasStores === 0,

      candidatoTesteEncontrado:
        Boolean(candidatoTeste),

      candidatoPossuiDataCorreta:
        candidatoTeste?.data ===
        dataRegistroTeste,

      candidatoAnteriorAoCorte:
        dataRegistroTeste <
        dataCorte,

      nenhumaGravacaoNaSimulacao:
        simulacao
          .gravacoesExecutadas === 0
    };


    const simulacaoAprovada =
      Object.values(
        validacoesSimulacao
      ).every(
        function (valor) {
          return valor === true;
        }
      );


    if (!simulacaoAprovada) {
      console.error(
        "[UX.20.2A] Simulação controlada reprovada:",
        validacoesSimulacao
      );

      throw new Error(
        "A simulação não identificou exclusivamente o registro temporário."
      );
    }


    /*
     * ======================================================
     * EXECUÇÃO REAL
     * ======================================================
     */

    execucao =
      await executarRetencaoLocalUX202_(
        simulacao.tokenPlano
      );


    /*
     * A rotina real já deve ter removido o registro.
     */
    registroInserido =
      false;


    /*
     * ======================================================
     * AUDITORIA FINAL
     * ======================================================
     */

    const estadoFinal =
      await capturarEstadoRetencaoUX202_();

    const assinaturasFinais =
      extrairAssinaturasUX202_(
        estadoFinal
      );

    const storesDivergentes =
      compararAssinaturasUX202_(
        assinaturasOriginais,
        assinaturasFinais
      );


    const registroAindaExiste =
      estadoFinal
        .TB_CLIMA
        .registros
        .some(
          function (registro) {
            return (
              textoUX202_(
                registro?.idClima
              ) === idTeste
            );
          }
        );


    const referenciasFilaDepois =
      localizarReferenciasTesteFilaUX202A_(
        estadoFinal
          .TB_SYNC_QUEUE
          .registros,
        idTeste
      );


    const validacoes = {
      naoHaviaCandidatosReais:
        planoOriginal.totalExcluir === 0,

      climaOriginal8:
        estadoOriginal
          .TB_CLIMA
          .quantidade === 8,

      inseriuExatamente1:
        estadoComTeste
          .TB_CLIMA
          .quantidade === 9,

      simulacaoIdentificou1:
        simulacao.totalExcluir === 1,

      simulacaoIdentificouSomenteClima:
        simulacao
          .porStore
          .TB_CLIMA === 1 &&
        candidatosOutrasStores === 0,

      execucaoAprovada:
        execucao.aprovado === true,

      executouExatamente1:
        execucao
          .gravacoesExecutadas === 1,

      removeuDaStoreCorreta:
        execucao
          .removidosPorStore
          ?.TB_CLIMA === 1,

      registroTemporarioRemovido:
        registroAindaExiste === false,

      climaRetornouPara8:
        estadoFinal
          .TB_CLIMA
          .quantidade === 8,

      nenhumaStoreFicouDivergente:
        storesDivergentes.length === 0,

      filaPermaneceu45:
        estadoFinal
          .TB_SYNC_QUEUE
          .quantidade === 45,

      filaSemReferenciaAoTeste:
        referenciasFilaDepois.length === 0,

      lotesPermaneceram0:
        estadoFinal
          .TB_LOTES_MEDICAO
          .quantidade === 0,

      notificacoesPermaneceram43:
        estadoFinal
          .TB_NOTIFICACOES
          .quantidade === 43,

      nenhumTombstoneCriado:
        registroAindaExiste === false
    };


    const aprovado =
      Object.values(
        validacoes
      ).every(
        function (valor) {
          return valor === true;
        }
      );


    const resultado = {
      etapa:
        "UX.20.2A",

      teste:
        "EXCLUSAO_EFETIVA_CONTROLADA",

      status:
        aprovado
          ? "APROVADO"
          : "REPROVADO",

      idObra:
        idObra,

      periodoDias:
        periodoDias,

      dataReferencia:
        dataReferencia,

      dataCorte:
        dataCorte,

      registroTeste: {
        id:
          idTeste,

        store:
          nomeStore,

        keyPath:
          keyPath,

        chave:
          chaveTeste,

        data:
          dataRegistroTeste,

        origem:
          "TESTE_CONTROLADO_UX202A"
      },

      fluxo: {
        totalClimaOriginal:
          estadoOriginal
            .TB_CLIMA
            .quantidade,

        totalClimaComTeste:
          estadoComTeste
            .TB_CLIMA
            .quantidade,

        totalClimaFinal:
          estadoFinal
            .TB_CLIMA
            .quantidade
      },

      simulacao: {
        status:
          simulacao.status,

        tokenPlano:
          simulacao.tokenPlano,

        totalExcluir:
          simulacao.totalExcluir,

        porStore:
          simulacao.porStore,

        candidatoTeste:
          candidatoTeste,

        gravacoesExecutadas:
          simulacao
            .gravacoesExecutadas
      },

      execucao: {
        status:
          execucao.status,

        gravacoesPlanejadas:
          execucao
            .gravacoesPlanejadas,

        gravacoesExecutadas:
          execucao
            .gravacoesExecutadas,

        removidosPorStore:
          execucao
            .removidosPorStore
      },

      storesFinais: {
        TB_CLIMA:
          estadoFinal
            .TB_CLIMA
            .quantidade,

        TB_SYNC_QUEUE:
          estadoFinal
            .TB_SYNC_QUEUE
            .quantidade,

        TB_LOTES_MEDICAO:
          estadoFinal
            .TB_LOTES_MEDICAO
            .quantidade,

        TB_NOTIFICACOES:
          estadoFinal
            .TB_NOTIFICACOES
            .quantidade
      },

      storesDivergentes:
        storesDivergentes,

      validacoes:
        validacoes,

      aprovado:
        aprovado
    };


    console.log(
      JSON.stringify(
        resultado,
        null,
        2
      )
    );


    if (!aprovado) {
      throw new Error(
        "UX.20.2A REPROVADA. Consulte as validações no console."
      );
    }


    console.log(
      "UX.20.2A — EXCLUSÃO EFETIVA CONTROLADA APROVADA."
    );

    return resultado;

  } catch (erro) {
    /*
     * ======================================================
     * LIMPEZA EMERGENCIAL
     * ======================================================
     *
     * Se o teste falhar antes da retenção remover o
     * registro, ele é excluído diretamente aqui.
     */

    if (
      registroInserido &&
      chaveTeste !== null
    ) {
      try {
        await excluirRegistroDiretoUX202A_(
          nomeStore,
          chaveTeste
        );

        await invalidarCacheTesteUX202A_(
          nomeStore,
          idObra
        );

        console.warn(
          "[UX.20.2A] Registro temporário removido pela limpeza emergencial."
        );

      } catch (erroLimpeza) {
        console.error(
          "[UX.20.2A] Falha na limpeza emergencial:",
          erroLimpeza
        );
      }
    }


    if (
      window.SIGO_UX202
    ) {
      window.SIGO_UX202
        .ultimaSimulacao =
          null;
    }


    console.error(
      "[UX.20.2A] Teste controlado interrompido:",
      erro
    );

    throw erro;
  }
}

/**
 * ============================================================
 * UX.20.3 — INTEGRAÇÃO VISUAL DA RETENÇÃO LOCAL
 * ============================================================
 *
 * Dependências:
 *
 * - UX.20.1 — configuração persistente;
 * - UX.20.2 — política segura de retenção;
 * - UX.20.2A — exclusão efetiva validada.
 *
 * A interface:
 *
 * - não executa limpeza automaticamente;
 * - exige simulação prévia;
 * - exige confirmação explícita;
 * - invalida a simulação quando obra ou período mudam;
 * - preserva o histórico da última execução no localStorage.
 */

const CHAVE_ULTIMA_RETENCAO_UX203 =
  "SIGO_ULTIMA_RETENCAO_LOCAL_V1";


/**
 * Normalização textual.
 */
function textoUX203_(valor) {
  return String(
    valor === undefined ||
    valor === null
      ? ""
      : valor
  ).trim();
}


/**
 * Escapa conteúdo antes da inserção em HTML.
 */
function escaparHtmlUX203_(valor) {
  return textoUX203_(valor)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}


/**
 * Formata YYYY-MM-DD para DD/MM/YYYY.
 */
function formatarDataUX203_(valor) {
  const data =
    normalizarDataUX202_(valor);

  if (!data) {
    return "Não disponível";
  }

  const partes =
    data.split("-");

  return (
    partes[2] +
    "/" +
    partes[1] +
    "/" +
    partes[0]
  );
}


/**
 * Formata uma data/hora para exibição local.
 */
function formatarDataHoraUX203_(valor) {
  if (!valor) {
    return "Nunca executada";
  }

  const data =
    new Date(valor);

  if (
    Number.isNaN(
      data.getTime()
    )
  ) {
    return "Nunca executada";
  }

  return data.toLocaleString(
    "pt-BR",
    {
      dateStyle:
        "short",

      timeStyle:
        "short"
    }
  );
}


/**
 * Obtém uma informação de obra a partir de
 * string ou objeto.
 */
function extrairIdObraUX203_(valor) {
  if (!valor) {
    return "";
  }

  if (
    typeof valor === "string"
  ) {
    const texto =
      valor.trim();

    if (
      /^OBR[A-Z0-9_-]*$/i.test(
        texto
      )
    ) {
      return texto;
    }

    try {
      return extrairIdObraUX203_(
        JSON.parse(texto)
      );

    } catch (erro) {
      return "";
    }
  }

  if (
    typeof valor === "object"
  ) {
    return textoUX203_(
      valor.idObra ??
      valor.ID_OBRA ??
      valor.codigoObra ??
      valor.obraAtiva ??
      valor.id
    );
  }

  return "";
}


/**
 * Resolve a obra ativa sem fixar OBR002.
 */
async function resolverIdObraAtivaUX203_() {
  const funcoesConhecidas = [
    "obterObraAtivaMobile_",
    "obterObraAtivaSIGO_",
    "obterObraAtiva_",
    "getObraAtiva"
  ];

  for (
    const nomeFuncao of
    funcoesConhecidas
  ) {
    if (
      typeof window[nomeFuncao] !==
      "function"
    ) {
      continue;
    }

    try {
      const retorno =
        await Promise.resolve(
          window[nomeFuncao]()
        );

      const idObra =
        extrairIdObraUX203_(
          retorno
        );

      if (idObra) {
        return idObra;
      }

    } catch (erro) {
      console.warn(
        "[UX.20.3] Leitura da obra ativa ignorada:",
        nomeFuncao,
        erro
      );
    }
  }


  const candidatosGlobais = [
    window.obraAtiva,
    window.OBRA_ATIVA,
    window.SIGO?.obraAtiva,
    window.SIGO?.contexto?.obraAtiva,
    window.SIGOContexto?.obraAtiva,
    window.SIGO_ESTADO?.obraAtiva,
    window.estadoMobile?.obraAtiva
  ];

  for (
    const candidato of
    candidatosGlobais
  ) {
    const idObra =
      extrairIdObraUX203_(
        candidato
      );

    if (idObra) {
      return idObra;
    }
  }


  const seletoresObra = [
    "#seletorObra",
    "#seletorObraMobile",
    "#selectObra",
    "#obraAtivaSelect",
    "#selectObraAtiva",
    'select[data-obra-ativa]',
    'select[id*="obra" i]'
  ];

  for (
    const seletor of
    seletoresObra
  ) {
    const elemento =
      document.querySelector(
        seletor
      );

    const idObra =
      extrairIdObraUX203_(
        elemento?.value
      );

    if (idObra) {
      return idObra;
    }
  }


  const chavesLocalStorage = [
    "SIGO_OBRA_ATIVA",
    "OBRA_ATIVA",
    "obraAtiva",
    "sigo_obra_ativa",
    "SIGO_CONTEXTO_OBRA"
  ];

  for (
    const chave of
    chavesLocalStorage
  ) {
    try {
      const idObra =
        extrairIdObraUX203_(
          localStorage.getItem(
            chave
          )
        );

      if (idObra) {
        return idObra;
      }

    } catch (erro) {
      // Continua procurando.
    }
  }

  throw new Error(
    "Não foi possível identificar a obra ativa para a retenção local."
  );
}


/**
 * Lê os metadados da última execução.
 */
function obterUltimaRetencaoUX203_() {
  try {
    return JSON.parse(
      localStorage.getItem(
        CHAVE_ULTIMA_RETENCAO_UX203
      ) || "null"
    );

  } catch (erro) {
    return null;
  }
}


/**
 * Salva os metadados da última execução real.
 */
function salvarUltimaRetencaoUX203_(
  execucao
) {
  const registro = {
    idObra:
      execucao.idObra,

    periodoDias:
      execucao.periodoDias,

    dataReferencia:
      execucao.dataReferencia,

    dataCorte:
      execucao.dataCorte,

    totalRemovido:
      Number(
        execucao.gravacoesExecutadas || 0
      ),

    removidosPorStore:
      execucao.removidosPorStore || {},

    tokenPlano:
      execucao.tokenPlano || "",

    executadoEm:
      new Date().toISOString()
  };

  localStorage.setItem(
    CHAVE_ULTIMA_RETENCAO_UX203,
    JSON.stringify(registro)
  );

  return registro;
}


/**
 * Localiza o modal ou container de reidratação.
 */
function obterContainerRetencaoUX203_() {
  const modal =
    document.getElementById(
      "modalReidratacaoUX1958"
    ) ||
    document.querySelector(
      '[id*="reidratacao" i][role="dialog"], ' +
      '[id*="reidrat" i].modal, ' +
      '[id*="reidrat" i].drawer, ' +
      '[id*="reidrat" i].sigo-modal'
    );

  if (modal) {
    return modal;
  }

  const select =
    typeof obterSelectPeriodoHistoricoUX201_ ===
      "function"
      ? obterSelectPeriodoHistoricoUX201_()
      : null;

  return (
    select?.closest(
      ".modal, .drawer, [role='dialog'], .sigo-modal"
    ) ||
    select?.parentElement ||
    null
  );
}


