/**
 * Atualiza o estilo do botão de execução.
 */
function definirBotaoExecucaoRetencaoUX203_(
  liberado
) {
  const botao =
    document.getElementById(
      "executarRetencaoUX203"
    );

  if (!botao) {
    return;
  }

  botao.disabled =
    !liberado;

  botao.style.opacity =
    liberado
      ? "1"
      : ".45";

  botao.style.cursor =
    liberado
      ? "pointer"
      : "not-allowed";
}


/**
 * Atualiza o selo de estado.
 */
function atualizarStatusRetencaoUX203_(
  texto,
  tipo = "NEUTRO"
) {
  const elemento =
    document.getElementById(
      "statusRetencaoUX203"
    );

  if (!elemento) {
    return;
  }

  const estilos = {
    NEUTRO: {
      fundo:
        "#e2e8f0",

      texto:
        "#475569"
    },

    PROCESSANDO: {
      fundo:
        "#fef3c7",

      texto:
        "#92400e"
    },

    APROVADO: {
      fundo:
        "#dcfce7",

      texto:
        "#166534"
    },

    ERRO: {
      fundo:
        "#fee2e2",

      texto:
        "#991b1b"
    }
  };

  const estilo =
    estilos[tipo] ||
    estilos.NEUTRO;

  elemento.textContent =
    texto;

  elemento.style.background =
    estilo.fundo;

  elemento.style.color =
    estilo.texto;
}


/**
 * Atualiza período, corte e última execução.
 */
async function atualizarCabecalhoRetencaoUX203_() {
  montarPainelRetencaoUX203_();

  const periodo =
    obterPeriodoHistoricoOfflineUX201_();

  const dataReferencia =
    obterDataLocalAtualUX202_();

  const dataCorte =
    calcularDataCorteUX202_(
      periodo,
      dataReferencia
    );

  const periodoElemento =
    document.getElementById(
      "periodoRetencaoUX203"
    );

  const corteElemento =
    document.getElementById(
      "dataCorteRetencaoUX203"
    );

  if (periodoElemento) {
    periodoElemento.textContent =
      periodo + " dias";
  }

  if (corteElemento) {
    corteElemento.textContent =
      formatarDataUX203_(
        dataCorte
      );
  }

  const ultima =
    obterUltimaRetencaoUX203_();

  const ultimaElemento =
    document.getElementById(
      "ultimaLimpezaRetencaoUX203"
    );

  if (ultimaElemento) {
    if (!ultima) {
      ultimaElemento.textContent =
        "Última limpeza local: nunca executada";

    } else {
      ultimaElemento.textContent =
        "Última limpeza local: " +
        formatarDataHoraUX203_(
          ultima.executadoEm
        ) +
        " • " +
        Number(
          ultima.totalRemovido || 0
        ) +
        " registro(s) removido(s)";
    }
  }

  return {
    periodoDias:
      periodo,

    dataReferencia:
      dataReferencia,

    dataCorte:
      dataCorte
  };
}


/**
 * Soma os removidos planejados por store.
 */
function montarListaPorStoreUX203_(
  porStore
) {
  const rotulos = {
    TB_DIARIOS:
      "Diários",

    TB_DIARIO_ITENS:
      "Itens de Diário",

    TB_OCORRENCIAS:
      "Ocorrências",

    TB_CLIMA:
      "Clima",

    TB_EVIDENCIAS:
      "Evidências",

    TB_MEDICOES:
      "Medições oficiais"
  };

  const linhas =
    Object.entries(
      porStore || {}
    )
      .filter(
        function (
          [, quantidade]
        ) {
          return Number(
            quantidade || 0
          ) > 0;
        }
      )
      .map(
        function (
          [store, quantidade]
        ) {
          return `
            <div style="
              display:flex;
              justify-content:space-between;
              gap:12px;
              padding:7px 0;
              border-bottom:1px solid #e2e8f0;
              font-size:12px;
            ">
              <span>
                ${escaparHtmlUX203_(
                  rotulos[store] || store
                )}
              </span>

              <strong>
                ${Number(quantidade || 0)}
              </strong>
            </div>
          `;
        }
      );

  if (!linhas.length) {
    return `
      <div style="
        padding:10px;
        border-radius:10px;
        background:#ecfdf5;
        color:#166534;
        font-size:12px;
        font-weight:700;
      ">
        Nenhum registro será removido.
      </div>
    `;
  }

  return linhas.join("");
}


/**
 * Agrupa motivos de proteção.
 */
function agruparProtecoesUX203_(
  registros
) {
  const contagem = {};

  (
    Array.isArray(registros)
      ? registros
      : []
  ).forEach(
    function (registro) {
      (
        Array.isArray(
          registro.motivos
        )
          ? registro.motivos
          : []
      ).forEach(
        function (motivo) {
          contagem[motivo] =
            Number(
              contagem[motivo] || 0
            ) + 1;
        }
      );
    }
  );

  return contagem;
}


